                <div className="h-full overflow-y-auto pr-2 custom-scrollbar">
                  <p className="text-slate-300 font-mono text-base leading-relaxed whitespace-pre-wrap">
                    {generatedPrompt}
                  </p>

                  <div className="mt-6 pt-4 border-t border-slate-700/50">
                    <h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Chi tiết Audio:</h4>
                    <div className="bg-slate-800/50 p-3 rounded-lg text-sm text-slate-400 space-y-1">
                       <p>• <b>Chế độ:</b> {hasVoice ? "Có lời thoại (Voiceover)" : "Chỉ âm thanh nền (SFX only)"}</p>
                       <p>• <b>Hiệu ứng SFX:</b> {selectedSoundEffects.length > 0 ? selectedSoundEffects.map(k => soundEffects[k].label.split(" / ")[0]).join(", ") : "Không chọn"}</p>
                       {hasVoice && (
                         <>
                            <p>• <b>Giọng đọc:</b> {voiceGender === 'male' ? 'Nam' : 'Nữ'} / {
                              voiceRegion === 'north' ? 'Miền Bắc' : voiceRegion === 'central' ? 'Miền Trung' : 'Miền Nam'
                            }</p>
                            <p>• <b>Tone:</b> {voiceAge === 'young' ? 'Trẻ trung' : voiceAge === 'middle' ? 'Trưởng thành' : 'Cao tuổi'}</p>
                         </>
                       )}
                    </div>
                  </div>
                </div>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-600 space-y-4">
                  <div className="w-16 h-16 rounded-full bg-slate-800 flex items-center justify-center">
                    <Sparkles className="w-8 h-8 opacity-50" />
                  </div>
                  <p className="text-center max-w-xs">
                    Điền thông tin sản phẩm và chọn kịch bản để tạo prompt.
                  </p>
                </div>
              )}
