                <div className="flex-1 lg:overflow-y-auto h-auto p-6 custom-scrollbar bg-gray-50">{renderResultModalContent()}</div>
                <div className="p-4 border-t border-gray-100 bg-white rounded-b-2xl flex justify-end"><button onClick={() => setShowResultModal(false)} className="px-6 py-2 bg-gray-100 hover:bg-gray-200 text-gray-700 font-bold rounded-xl transition-colors font-display">Đóng</button></div>
            </div>
        </div>
      )}
    </div>
  );
};

