        </div>

        {/* --- MAIN CONTENT AREA --- */}
        <div className="flex-1 flex flex-col lg:overflow-hidden relative bg-white h-auto">

            <div className="flex-1 lg:overflow-hidden relative h-auto">
                {/* TAB: Fashion Studio */}
                {activeTab === 'studio' && (
                  <div className="lg:h-full h-auto grid grid-cols-1 lg:grid-cols-12 divide-y lg:divide-y-0 lg:divide-x divide-gray-200">
                      {/* COLUMN 1: UPLOADS */}
                      <div className="lg:col-span-3 p-4 flex flex-col gap-4 lg:overflow-y-auto h-auto custom-scrollbar bg-slate-50/50">
                          <div className="flex items-center gap-2 mb-1">
                              <span className="bg-orange-100 text-orange-700 w-6 h-6 rounded-full flex items-center justify-center text-xs font-display font-bold">1</span>
