                                      {BACKDROPS.map((item) => (
                                          <div key={item.id} onClick={() => setSelectedBackdrop(item)} className={`p-2 rounded-lg cursor-pointer border text-xs transition-all h-full ${selectedBackdrop.id === item.id ? 'border-orange-500 bg-orange-50 shadow-sm' : 'border-gray-100 hover:bg-gray-50'}`}>
