      });

      const jsonText = response.text || "{}";
      setResult(JSON.parse(jsonText));
    } catch (err) { 
        console.error(err);
        setError('Lỗi kết nối AI. Vui lòng thử lại.'); 
    } finally { setLoading(false); }
  };

  // --- Logic Tab 2: Remix Image ---

  // Helper: Resize and Pad image to target Aspect Ratio with PADDING (Crucial for Full Background)
  const resizeImageToAspectRatio = (base64Str: string, ratioId: string): Promise<string> => {
    return new Promise((resolve) => {
      const img = new Image();
      img.src = base64Str;
      img.onload = () => {
        const canvas = document.createElement('canvas');

        let targetRatio = 1;
        if (ratioId === '9:16') targetRatio = 9/16;
        else if (ratioId === '4:5') targetRatio = 4/5;
        else if (ratioId === '16:9') targetRatio = 16/9;

        // Calculate Canvas Dimensions
        let canvasW, canvasH;
        const currentRatio = img.width / img.height;

        if (currentRatio > targetRatio) {
            canvasW = img.width;
            canvasH = img.width / targetRatio;
        } else {
            canvasH = img.height;
            canvasW = img.height * targetRatio;
        }

        canvas.width = canvasW;
        canvas.height = canvasH;

        const ctx = canvas.getContext('2d');
        if (ctx) {
            // Fill background white
            ctx.fillStyle = "#FFFFFF"; 
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // SCALE DOWN product to 85% of the frame
            // This padding ensures the product doesn't touch edges, forcing AI to generate new background
            const scaleFactor = 0.85; 
            const scale = Math.min(canvasW / img.width, canvasH / img.height) * scaleFactor;

            const w = img.width * scale;
            const h = img.height * scale;
            const x = (canvasW - w) / 2;
            const y = (canvasH - h) / 2;

            ctx.drawImage(img, x, y, w, h);

            resolve(canvas.toDataURL('image/png'));
        }
      };
    });
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUploadedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const generateRemixImage = async () => {
    if (!uploadedImage) { setError('Vui lòng tải ảnh sản phẩm lên!'); return; }
    setError(''); setLoading(true); setGeneratedImage(null); setRemixCaption(''); setSoraPrompt('');

    const selectedStyle = stylesList.find(s => s.id === style) || stylesList[0];
    const selectedOccasion = occasions.find(o => o.id === occasion) || occasions[0];

    // 1. Resize image first to match target aspect ratio (Input Pre-processing)
    const processedImageBase64Full = await resizeImageToAspectRatio(uploadedImage, aspectRatio);

    // Tách base64 data từ ảnh đã xử lý
    const base64Data = processedImageBase64Full.split(',')[1];

    // 2. Build Prompt - STRICTLY enforced
    let promptStyleContext = "";
    if (selectedStyle.id === 'luxury') {
        promptStyleContext = "Luxury Style: High-end, sophisticated, dark or gold tones, elegant lighting, premium materials like marble or silk.";
    } else if (selectedStyle.id === 'minimalist') {
        promptStyleContext = "Minimalist Style: Clean, simple, soft neutral colors, plenty of negative space, soft natural lighting.";
    } else if (selectedStyle.id === 'cute') {
        promptStyleContext = "Cute & Playful Style: Pastel colors, soft lighting, adorable props, cheerful atmosphere.";
    } else if (selectedStyle.id === 'vintage') {
        promptStyleContext = "Vintage Style: Nostalgic, warm film grain, retro props, classic atmosphere.";
    } else if (selectedStyle.id === 'futuristic') {
        promptStyleContext = "Futuristic/Cyberpunk Style: Neon lights, technological elements, sleek surfaces, modern vibe.";
    } else if (selectedStyle.id === 'natural') {
        promptStyleContext = "Organic/Nature Style: Greenery, wood textures, sunlight, fresh outdoor feel.";
    }

    let promptOccasionContext = "";
    if (selectedOccasion.id === 'tet') {
        promptOccasionContext = "Theme: Lunar New Year (Tet Holiday). Red and gold colors, lucky money envelopes, peach blossoms/ochna flowers.";
    } else if (selectedOccasion.id === 'christmas') {
        promptOccasionContext = "Theme: Christmas. Pine trees, snow, warm fireplace, gift boxes, cozy winter vibes.";
    } else if (selectedOccasion.id === 'valentine') {
        promptOccasionContext = "Theme: Valentine's Day. Hearts, roses, pink and red tones, romantic atmosphere.";
    } else if (selectedOccasion.id === 'mid_autumn') {
        promptOccasionContext = "Theme: Mid-Autumn Festival. Mooncakes, lanterns, full moon, warm night setting.";
    }

    // UPDATED PROMPT: Added strict cleanup instructions and FULL BACKGROUND enforcement
    const fullPrompt = `
      Professional Product Photography Generation - Background Replacement & Outpainting.

      INPUT IMAGE: A product centered on a placeholder background.
      TARGET ASPECT RATIO: ${aspectRatio}

      CRITICAL INSTRUCTION:
      1. IGNORE/REMOVE the existing white/plain background of the input image.
      2. GENERATE a fully detailed, high-quality environment that extends to ALL FOUR EDGES of the frame.
      3. NO WHITE BARS, NO BORDERS, NO PADDING. The scene must be FULL BLEED.
      4. SUBJECT FOCUS: Keep ONLY the product itself in the center.

      VISUAL SETTING:
      - Style: ${promptStyleContext}
      - Context/Occasion: ${promptOccasionContext || "Commercial advertising setting."}
      - Lighting: Professional studio or natural lighting matching the scene.

      STRICT CLEANUP RULES:
      - REMOVE hands, fingers, or stands holding the product. The product should float or sit naturally.
      - REMOVE any existing text/watermarks from the background.

      NEGATIVE PROMPT:
      white background, plain background, white bars, letterboxing, cropped, borders, frame, text, watermark, hand, fingers, holding, low quality, blurry, empty white space.
    `;

    // 3. Determine API Aspect Ratio config
    // Map custom UI ratios to API supported values (1:1, 3:4, 4:3, 9:16, 16:9)
    let apiAspectRatio = aspectRatio;
    if (aspectRatio === '4:5') {
        apiAspectRatio = '3:4'; // Closest supported vertical ratio for 4:5
    }

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
              parts: [
                  { text: fullPrompt },
                  { inlineData: { mimeType: 'image/png', data: base64Data } }
              ]
          },
          config: {
              responseModalities: ['IMAGE'],
              imageConfig: {
                  aspectRatio: apiAspectRatio // FORCE API to output correct ratio
              }
          }
      });

      const parts = response.candidates?.[0]?.content?.parts;
      if (parts) {
          for (const part of parts) {
              if (part.inlineData && part.inlineData.data) {
                  setGeneratedImage(`data:image/png;base64,${part.inlineData.data}`);
                  return;
              }
          }
      }
      throw new Error("AI không trả về hình ảnh.");
    } catch (err) {
      console.error(err);
      setError('Có lỗi xảy ra khi tạo ảnh. Hãy thử lại!');
    } finally {
      setLoading(false);
    }
  };

  const handleGenerateRemixCaption = async () => {
    setGeneratingCaption(true);
    const selectedStyle = stylesList.find(s => s.id === style) || stylesList[0];
    const selectedOccasion = occasions.find(o => o.id === occasion) || occasions[0];

    const prompt = `
    Đóng vai chuyên gia Content Creator trên TikTok.
    Viết 1 caption viral, hấp dẫn cho bức ảnh sản phẩm vừa được tạo.

    Thông tin ngữ cảnh:
    - Phong cách ảnh: ${selectedStyle.name}
    - Bối cảnh/Dịp: ${selectedOccasion.name}

    Yêu cầu:
    - Ngắn gọn (dưới 50 từ), giọng văn vui vẻ, bắt trend Gen Z.
    - Kêu gọi hành động (CTA) khéo léo.
    - Kèm 3-5 hashtag liên quan và trendy.
    - Chỉ trả về nội dung caption và hashtag.
    `;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
