import { generateCompositeImage } from './services/geminiService';
import { ImageUploader } from './components/ImageUploader';
import { AIImageGenerator } from './components/AIImageGenerator';
import { ContentGeniusAI } from './components/ContentGeniusAI';
import { TextToSpeech } from './components/TextToSpeech';
import { PromptBuilder } from './components/PromptBuilder';
import { VirtualTryOn } from './components/VirtualTryOn';
import { UserGuide } from './components/UserGuide';
import { SoraPromptGen } from './components/SoraPromptGen';

const App: React.FC = () => {
  // Tabs update - Removed 'virtual_try_on' from main tabs, merged into 'studio'
  const [activeTab, setActiveTab] = useState<'studio' | 'ai_image_generator' | 'content_genius' | 'text_to_speech' | 'prompt_builder' | 'sora_prompt_gen'>('studio');

  // Studio Sub-mode state
  const [studioMode, setStudioMode] = useState<'composite' | 'try_on'>('composite');

  // --- Fashion Studio (Composite) State ---
  const [personImage, setPersonImage] = useState<ProcessedImage | null>(null);
  const [productImage, setProductImage] = useState<ProcessedImage | null>(null);
  const [customBackdropImage, setCustomBackdropImage] = useState<ProcessedImage | null>(null);
  const [resultImage, setResultImage] = useState<string | null>(null);

  const [selectedOutfit, setSelectedOutfit] = useState<OptionItem>(OUTFITS[0]);
  const [selectedPose, setSelectedPose] = useState<OptionItem>(POSES[0]);
  const [selectedBackdrop, setSelectedBackdrop] = useState<OptionItem>(BACKDROPS[0]);
  const [selectedExpression, setSelectedExpression] = useState<OptionItem>(EXPRESSIONS[0]);
  const [selectedAspectRatio, setSelectedAspectRatio] = useState<OptionItem>(ASPECT_RATIOS[0]);

  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState('');
  const [statusMessage, setStatusMessage] = useState('');

  const processFile = (file: File): Promise<ProcessedImage> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        if (event.target?.result) {
            img.src = event.target.result as string;
            img.onload = () => {
              const canvas = document.createElement('canvas');
              const MAX_WIDTH = 1024; 
              const scaleSize = MAX_WIDTH / Math.max(img.width, MAX_WIDTH);
              canvas.width = img.width * scaleSize;
              canvas.height = img.height * scaleSize;
              const ctx = canvas.getContext('2d');
              if (ctx) {
                  ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
                  const dataUrl = canvas.toDataURL(file.type);
                  resolve({
                    preview: dataUrl,
                    base64: dataUrl.split(',')[1],
                    mimeType: file.type
                  });
              } else {
                  reject(new Error("Canvas context failed"));
              }
            };
            img.onerror = (e) => reject(e);
        }
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, type: 'person' | 'product' | 'bg') => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      setError('');
      const processed = await processFile(file);
      if (type === 'person') {
        setPersonImage(processed);
      } else if (type === 'product') {
        setProductImage(processed);
      } else if (type === 'bg') {
        setCustomBackdropImage(processed);
      }
      setResultImage(null);
    } catch (err) {
      console.error(err);
      setError('Lỗi xử lý ảnh. Vui lòng thử file khác.');
    }
  };

  const handleGenerate = async () => {
    if (!personImage || !productImage) {
      setError('Vui lòng tải lên cả ảnh người mẫu và ảnh sản phẩm.');
      return;
    }

    if (selectedBackdrop.id === 'custom_bg' && !customBackdropImage) {
        setError('Vui lòng tải lên ảnh nền tùy chọn hoặc chọn bối cảnh có sẵn.');
        return;
    }

    setIsGenerating(true);
    setError('');
    setResultImage(null);
    setStatusMessage('Đang phân tích...');

    try {
      setTimeout(() => setStatusMessage('Đang xử lý ảnh...'), 2000);

      const result = await generateCompositeImage({
          personImage,
          productImage,
          customBackdrop: selectedBackdrop.id === 'custom_bg' ? customBackdropImage : null,
          outfit: selectedOutfit,
          pose: selectedPose,
          backdrop: selectedBackdrop,
          expression: selectedExpression,
          aspectRatio: selectedAspectRatio
      });

      setResultImage(result);
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Tạo ảnh thất bại. Vui lòng thử lại.');
    } finally {
      setIsGenerating(false);
      setStatusMessage('');
    }
  };

  const handleReset = () => {
    setPersonImage(null);
    setProductImage(null);
    setCustomBackdropImage(null);
    setResultImage(null);
    setError('');
    setSelectedOutfit(OUTFITS[0]);
    setSelectedPose(POSES[0]);
    setSelectedBackdrop(BACKDROPS[0]);
    setSelectedExpression(EXPRESSIONS[0]);
    setSelectedAspectRatio(ASPECT_RATIOS[0]);
  };

  const downloadImage = () => {
    if (resultImage) {
      const link = document.createElement('a');
      link.href = resultImage;
      link.download = `studio-gen-${selectedBackdrop.id}-${Date.now()}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  return (
    // Consistent Orange/Amber Gradient Background for ALL tabs
    <div className="lg:h-screen min-h-screen font-body text-gray-800 p-2 md:p-4 lg:overflow-hidden flex flex-col transition-colors duration-500 bg-gradient-to-br from-orange-50 via-white to-amber-50">

      <div className="max-w-[1920px] w-full mx-auto bg-white/90 backdrop-blur-xl rounded-[1.5rem] shadow-2xl border border-white/50 flex flex-col lg:h-full h-auto lg:overflow-hidden">

        {/* Compact Header - Consistent Orange Gradient */}
        <div className="flex-none px-6 py-3 text-white flex flex-col md:flex-row items-center justify-between gap-4 shadow-md z-20 bg-gradient-to-r from-orange-600 to-amber-600">
            <div className="flex items-center gap-3">
                <div className="bg-white/20 p-2 rounded-lg"><Sparkles className="text-yellow-200 w-5 h-5" /></div>
                <h1 className="text-xl font-display font-extrabold tracking-tight">SỨC MẠNH AI - by Nam Lê 098.102.8794 </h1>
            </div>

            {/* Navigation Tabs */}
            <div className="flex gap-1 overflow-x-auto w-full md:w-auto pb-1 md:pb-0 custom-scrollbar">
                {[
                  { id: 'studio', label: 'Fashion Studio', icon: Shirt }, // Renamed & Merged
                  { id: 'ai_image_generator', label: 'Tạo Ảnh AI', icon: Camera },
                  { id: 'content_genius', label: 'Content', icon: PenTool },
                  { id: 'text_to_speech', label: 'Giọng Đọc', icon: Mic },
                  { id: 'prompt_builder', label: 'Prompt AI', icon: Lightbulb },
                  { id: 'sora_prompt_gen', label: 'Sora Video', icon: Video }
                ].map(tab => {
                   const isActive = activeTab === tab.id;

                   return (
                   <button 
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id as any)}
                    className={`px-3 py-1.5 rounded-lg text-sm font-display font-bold flex items-center gap-2 transition-all whitespace-nowrap
                    ${isActive 
                        ? 'bg-white text-orange-700 shadow-sm' 
                        : 'text-white/80 hover:bg-white/10'}`}
                >
                    <tab.icon size={16} />
                    {tab.label}
                </button>
                )})}
            </div>
        </div>

        {/* --- MAIN CONTENT AREA --- */}
        <div className="flex-1 flex flex-col lg:overflow-hidden relative bg-white h-auto">

            <div className="flex-1 lg:overflow-hidden relative h-auto">
                {/* TAB: Fashion Studio (Merged) */}
                {activeTab === 'studio' && (
                  <div className="flex flex-col h-full">
                      {/* Sub-navigation for Studio Modes */}
                      <div className="flex-none p-3 border-b border-orange-100 bg-orange-50 flex justify-center">
                          <div className="bg-white p-1 rounded-xl border border-orange-200 shadow-sm flex gap-1">
                              <button 
                                  onClick={() => setStudioMode('composite')}
                                  className={`px-6 py-2 rounded-lg text-sm font-display font-bold flex items-center gap-2 transition-all whitespace-nowrap ${studioMode === 'composite' ? 'bg-gradient-to-r from-orange-500 to-amber-500 text-white shadow-md' : 'text-gray-500 hover:bg-orange-50'}`}
                              >
                                  <Layers size={16} /> Ghép Mặt & Bối Cảnh
                              </button>
                              <button 
                                  onClick={() => setStudioMode('try_on')}
                                  className={`px-6 py-2 rounded-lg text-sm font-display font-bold flex items-center gap-2 transition-all whitespace-nowrap ${studioMode === 'try_on' ? 'bg-gradient-to-r from-orange-500 to-amber-500 text-white shadow-md' : 'text-gray-500 hover:bg-orange-50'}`}
                              >
                                  <Wand2 size={16} /> Phòng Thử Đồ Ảo
                              </button>
                          </div>
                      </div>

                      <div className="flex-1 min-h-0 lg:overflow-hidden relative">
                        {studioMode === 'composite' ? (
                            /* --- MODE 1: COMPOSITE (Old Studio Logic) --- */
                            <div className="lg:h-full h-auto grid grid-cols-1 lg:grid-cols-12 divide-y lg:divide-y-0 lg:divide-x divide-gray-200">
                                {/* COLUMN 1: UPLOADS */}
                                <div className="lg:col-span-3 p-4 flex flex-col gap-4 lg:overflow-y-auto h-auto custom-scrollbar bg-slate-50/50">
                                    <div className="flex items-center gap-2 mb-1">
                                        <span className="bg-orange-100 text-orange-700 w-6 h-6 rounded-full flex items-center justify-center text-xs font-display font-bold">1</span>
                                        <h3 className="font-display font-bold text-gray-700 text-sm uppercase">Lựa chọn</h3>
                                    </div>

                                    <div className="space-y-4">
                                      <ImageUploader 
                                          label="Ảnh Nhân vật (Chỉ tải khuôn mặt)" 
                                          icon={<User size={14} className="text-orange-600" />}
                                          image={personImage}
                                          onUpload={(e) => handleFileUpload(e, 'person')}
                                          onRemove={() => setPersonImage(null)}
                                          colorClass="text-orange-600"
                                          bgColorClass="bg-orange-50"
                                          borderColorClass="border-orange-400"
                                          heightClass="h-48"
                                      />
                                      <ImageUploader 
                                          label="Ảnh Sản Phẩm (Cắt ảnh sát hình)" 
                                          icon={<Box size={14} className="text-amber-600" />}
                                          image={productImage}
                                          onUpload={(e) => handleFileUpload(e, 'product')}
                                          onRemove={() => setProductImage(null)}
                                          colorClass="text-amber-600"
                                          bgColorClass="bg-amber-50"
                                          borderColorClass="border-amber-400"
                                          heightClass="h-48"
                                      />
                                      {error && (
                                        <div className="flex items-start gap-2 text-red-700 bg-red-50 p-3 rounded-lg border border-red-100 text-xs">
                                            <AlertCircle size={14} className="shrink-0 mt-0.5" />
                                            <span className="font-medium leading-tight">{error}</span>
                                        </div>
                                      )}
                                    </div>
                                </div>

                                {/* COLUMN 2: CONFIG */}
                                <div className="lg:col-span-5 p-4 lg:overflow-y-auto h-auto custom-scrollbar bg-white">
                                    <div className="flex items-center gap-2 mb-4 lg:sticky lg:top-0 static bg-white z-10 py-1">
                                        <span className="bg-orange-100 text-orange-700 w-6 h-6 rounded-full flex items-center justify-center text-xs font-display font-bold">2</span>
                                        <h3 className="font-display font-bold text-gray-700 text-sm uppercase">Cấu Hình Studio</h3>
                                    </div>

                                    <div className="space-y-6">
                                        <div className="grid grid-cols-2 gap-4">
                                            <div className="space-y-2">
                                                <label className="flex items-center gap-1.5 font-display font-bold text-gray-600 text-xs uppercase"><Shirt size={14}/> Trang phục</label>
                                                <div className="space-y-1.5 max-h-40 overflow-y-auto custom-scrollbar border border-gray-100 rounded-xl p-1">
                                                    {OUTFITS.map((item) => (
                                                        <div key={item.id} onClick={() => setSelectedOutfit(item)} className={`p-2 rounded-lg cursor-pointer border text-xs transition-all ${selectedOutfit.id === item.id ? 'border-orange-500 bg-orange-50 shadow-sm' : 'border-transparent hover:bg-gray-50'}`}>
                                                            <div className="font-bold font-display">{item.label}</div>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>

                                            <div className="space-y-2">
                                                <label className="flex items-center gap-1.5 font-display font-bold text-gray-600 text-xs uppercase"><Hand size={14}/> Dáng tay</label>
                                                <div className="space-y-1.5 max-h-40 overflow-y-auto custom-scrollbar border border-gray-100 rounded-xl p-1">
                                                    {POSES.map((item) => (
                                                        <div key={item.id} onClick={() => setSelectedPose(item)} className={`p-2 rounded-lg cursor-pointer border text-xs transition-all ${selectedPose.id === item.id ? 'border-amber-500 bg-amber-50 shadow-sm' : 'border-transparent hover:bg-gray-50'}`}>
                                                            <div className="font-bold font-display">{item.label}</div>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>

                                            <div className="space-y-2">
                                                <label className="flex items-center gap-1.5 font-display font-bold text-gray-600 text-xs uppercase"><Smile size={14}/> Biểu cảm</label>
                                                <div className="space-y-1.5 max-h-40 overflow-y-auto custom-scrollbar border border-gray-100 rounded-xl p-1">
                                                    {EXPRESSIONS.map((item) => (
                                                        <div key={item.id} onClick={() => setSelectedExpression(item)} className={`p-2 rounded-lg cursor-pointer border text-xs transition-all ${selectedExpression.id === item.id ? 'border-orange-500 bg-orange-50 shadow-sm' : 'border-transparent hover:bg-gray-50'}`}>
                                                            <div className="font-bold font-display">{item.label}</div>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>

                                            <div className="space-y-2">
                                                <label className="flex items-center gap-1.5 font-display font-bold text-gray-600 text-xs uppercase"><Crop size={14}/> Tỷ lệ</label>
                                                <div className="space-y-1.5 max-h-40 overflow-y-auto custom-scrollbar border border-gray-100 rounded-xl p-1">
                                                    {ASPECT_RATIOS.map((item) => (
                                                        <div key={item.id} onClick={() => setSelectedAspectRatio(item)} className={`p-2 rounded-lg cursor-pointer border text-xs transition-all ${selectedAspectRatio.id === item.id ? 'border-amber-500 bg-amber-50 shadow-sm' : 'border-transparent hover:bg-gray-50'}`}>
                                                            <div className="font-bold font-display">{item.label}</div>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        </div>

                                        <div className="space-y-2">
                                            <label className="flex items-center gap-1.5 font-display font-bold text-gray-600 text-xs uppercase"><Layers size={14}/> Bối cảnh / Nền</label>
                                            <div className="grid grid-cols-2 gap-2 max-h-60 overflow-y-auto custom-scrollbar border border-gray-100 rounded-xl p-2">
                                                {BACKDROPS.map((item) => (
                                                    <div key={item.id} onClick={() => setSelectedBackdrop(item)} className={`p-2 rounded-lg cursor-pointer border text-xs transition-all h-full ${selectedBackdrop.id === item.id ? 'border-orange-500 bg-orange-50 shadow-sm' : 'border-gray-100 hover:bg-gray-50'}`}>
                                                        <div className="font-bold font-display text-gray-800">{item.label}</div>
                                                        <div className="text-gray-500 text-[10px] line-clamp-2 mt-0.5">{item.desc}</div>
                                                    </div>
                                                ))}
                                            </div>

                                            {selectedBackdrop.id === 'custom_bg' && (
                                              <div className="mt-4 animate-in fade-in slide-in-from-top-2">
                                                <ImageUploader 
                                                    label="Tải Ảnh Nền Của Bạn" 
                                                    icon={<ImageIcon size={14} className="text-orange-600" />}
                                                    image={customBackdropImage}
                                                    onUpload={(e) => handleFileUpload(e, 'bg')}
                                                    onRemove={() => setCustomBackdropImage(null)}
                                                    colorClass="text-orange-600"
                                                    bgColorClass="bg-orange-50"
                                                    borderColorClass="border-orange-400"
                                                    heightClass="h-32"
                                                />
                                              </div>
                                            )}
                                        </div>
                                    </div>
                                </div>

                                {/* COLUMN 3: RESULT */}
                                <div className="lg:col-span-4 p-4 flex flex-col gap-4 bg-slate-50/30 lg:h-full h-auto lg:overflow-y-auto custom-scrollbar">
                                    <div className="flex items-center gap-2 mb-1 shrink-0">
                                        <span className="bg-orange-100 text-orange-700 w-6 h-6 rounded-full flex items-center justify-center text-xs font-display font-bold">3</span>
                                        <h3 className="font-display font-bold text-gray-700 text-sm uppercase">Kết Quả</h3>
                                    </div>

                                    <button
                                      onClick={handleGenerate}
                                      disabled={!personImage || !productImage || isGenerating || (selectedBackdrop.id === 'custom_bg' && !customBackdropImage)}
                                      className={`
                                      w-full py-3 rounded-xl text-sm font-display font-bold text-white shadow-lg transition-all transform flex-none
                                      ${(!personImage || !productImage || (selectedBackdrop.id === 'custom_bg' && !customBackdropImage))
                                          ? 'bg-gray-300 cursor-not-allowed' 
                                          : isGenerating 
                                          ? 'bg-gray-800 cursor-wait' 
                                          : 'bg-gradient-to-r from-orange-600 to-amber-600 hover:scale-[1.02] active:scale-95'}
                                      `}
                                  >
                                      <div className="flex items-center justify-center gap-2">
                                      {isGenerating ? <RefreshCw className="animate-spin" size={18} /> : <Sparkles size={18} />}
                                      {isGenerating ? statusMessage || 'Đang xử lý...' : 'GHÉP ẢNH NGAY'}
                                      </div>
                                  </button>

                                  {resultImage && (
                                      <div className="flex flex-col sm:flex-row justify-center gap-3 w-full animate-in fade-in slide-in-from-top-2">
                                          <button onClick={downloadImage} className="flex-1 bg-white border border-gray-200 text-gray-900 px-4 py-3 rounded-xl text-xs font-bold font-display flex items-center justify-center gap-2 shadow-sm hover:bg-gray-50 hover:shadow-md transition-all">
                                              <Download size={16} /> Tải Về Máy
                                          </button>
                                          <button onClick={handleReset} className="flex-1 bg-gray-900 text-white px-4 py-3 rounded-xl text-xs font-bold font-display flex items-center justify-center gap-2 shadow-lg hover:bg-black hover:scale-[1.02] transition-all">
                                              <RefreshCw size={16} /> Làm Mới
                                          </button>
                                      </div>
                                  )}

                                  <div className="w-full bg-slate-100 rounded-2xl border-2 border-dashed border-slate-300 flex flex-col items-center justify-center relative overflow-hidden group min-h-[400px]">
                                      {resultImage ? (
                                          <div className="w-full h-full flex flex-col p-4 gap-4">
                                              <div className="relative w-full flex-1 flex items-center justify-center bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]">
                                                <img 
                                                    src={resultImage} 
                                                    alt="Kết Quả" 
                                                    className="w-full h-auto max-h-none object-contain shadow-2xl rounded-lg" 
                                                />
                                              </div>
                                          </div>
                                      ) : (
                                          <div className="text-center text-gray-400 p-6 absolute inset-0 flex flex-col items-center justify-center">
                                              <ImageIcon size={48} className="mx-auto mb-3 opacity-30 text-slate-400" />
                                              <p className="text-sm font-bold font-display text-slate-500">Chưa Có Ảnh</p>
                                              <p className="text-xs mt-1 text-slate-400 font-body">Kết quả sẽ hiển thị ở đây với chất lượng cao nhất</p>
                                          </div>
                                      )}
                                  </div>
                                </div>
                            </div>
                        ) : (
                            /* --- MODE 2: VIRTUAL TRY-ON (Imported Component) --- */
                            <div className="h-full custom-scrollbar">
                                <VirtualTryOn />
                            </div>
                        )}
                      </div>
                  </div>
                )}

                {/* OTHER TABS */}
                {activeTab === 'ai_image_generator' && <div className="lg:h-full h-auto custom-scrollbar"><AIImageGenerator /></div>}
                {activeTab === 'content_genius' && <div className="lg:h-full h-auto custom-scrollbar"><ContentGeniusAI /></div>}
                {activeTab === 'text_to_speech' && <div className="lg:h-full h-auto lg:overflow-y-auto p-4 md:p-8 custom-scrollbar"><TextToSpeech /></div>}
                {activeTab === 'prompt_builder' && <div className="lg:h-full h-auto lg:overflow-y-auto p-0 custom-scrollbar"><PromptBuilder /></div>}
                {activeTab === 'sora_prompt_gen' && <div className="lg:h-full h-auto lg:overflow-y-auto p-0 custom-scrollbar"><SoraPromptGen /></div>}
            </div>

            {/* Contextual User Guide at the bottom */}
            <UserGuide activeTab={activeTab} />

        </div>
      </div>
    </div>
  );
};

export default App;

