    <script>
        // API Configuration
        const apiKey = ""; // API Key will be injected by the environment

        let currentHookText = "";

        const tips = [
            "Mẹo AI: Đôi khi AI viết hơi dài, bạn có thể tự cắt ngắn bớt cho súc tích.",
            "Mẹo AI: Nếu Hook chưa đủ 'phê', hãy thử đổi phong cách sang 'Drama' hoặc 'Nỗi sợ'.",
            "Mẹo AI: Thêm các con số cụ thể vào mô tả sản phẩm để AI viết chính xác hơn.",
            "Mẹo AI: Nếu chữ trên ảnh bị lỗi dấu, hãy thử bấm 'Vẽ Ảnh' lại lần nữa."
        ];

        function getRandom(arr) {
            return arr[Math.floor(Math.random() * arr.length)];
        }

        // --- 1. Generate Hook ---
        async function generateAIHook() {
            let product = document.getElementById('productName').value.trim();
            let desc = document.getElementById('productDesc').value.trim();
            let style = document.getElementById('hookType').value;
            const btn = document.getElementById('generateBtn');
            const btnText = document.getElementById('btnText');
            const resultArea = document.getElementById('resultArea');
            const hookOutput = document.getElementById('hookOutput');

            // Reset other sections
            document.getElementById('scriptArea').classList.add('hidden');
            document.getElementById('imageSection').classList.add('hidden');

            if (!product) { alert("Bạn ơi, nhập tên sản phẩm giúp mình với!"); return; }
            if (!desc) desc = "giải quyết vấn đề của khách hàng"; 

            btn.disabled = true;
            btnText.innerHTML = '<div class="loader inline-block mr-2"></div> Đang suy nghĩ...';

            if (resultArea.classList.contains('hidden')) {
                resultArea.classList.remove('hidden');
                resultArea.classList.add('animate-fade-in');
            }
            hookOutput.innerHTML = '<span class="text-gray-300 text-lg font-normal animate-pulse">Đang kết nối với vũ trụ...</span>';

            const prompt = `
                Bạn là một chuyên gia Copywriter. Viết DUY NHẤT 01 tiêu đề thu hút (Hook) bằng Tiếng Việt.
                Sản phẩm: ${product}. Mô tả: ${desc}.
                Phong cách: ${style}. Tiêu đề phải gây sốc, tò mò, không dùng dấu ngoặc kép.
            `;

            try {
                const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-09-2025:generateContent?key=${apiKey}`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ contents: [{ parts: [{ text: prompt }] }] })
                });

                if (!response.ok) throw new Error('API Error');

                const data = await response.json();
                const aiText = data.candidates[0].content.parts[0].text.trim();

                currentHookText = aiText;
                hookOutput.innerText = aiText;
                document.getElementById('hookBadge').innerText = `AI Style: ${style.toUpperCase()}`;
                document.getElementById('hookTip').innerText = getRandom(tips);

            } catch (error) {
                console.error(error);
                hookOutput.innerText = "Lỗi kết nối. Thử lại giúp mình nhé!";
            } finally {
                btn.disabled = false;
                btnText.innerHTML = '<i class="fas fa-bolt"></i> Hỏi AI Viết Hook';
            }
        }

        // --- 2. Generate Voiceover Script ---
        async function generateScript() {
            if (!currentHookText) return;
            let product = document.getElementById('productName').value.trim();
            let desc = document.getElementById('productDesc').value.trim();
            const btn = document.getElementById('scriptBtn');
            const scriptArea = document.getElementById('scriptArea');
            const scriptContent = document.getElementById('scriptContent');

            const originalBtnText = btn.innerHTML;
            btn.disabled = true;
            btn.innerHTML = '<div class="loader inline-block mr-2"></div> Đang viết...';

            const prompt = `
                Dựa vào Hook: "${currentHookText}" và Sản phẩm: "${product}" - ${desc}.
                Viết KỊCH BẢN LỜI BÌNH (Voiceover) cho video giấu mặt (30-45s).
                Chỉ viết lời thoại, không viết chỉ dẫn hình ảnh. Giọng tự nhiên.
            `;

            try {
                const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-09-2025:generateContent?key=${apiKey}`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ contents: [{ parts: [{ text: prompt }] }] })
                });

                const data = await response.json();
                const aiScript = data.candidates[0].content.parts[0].text.trim();
                scriptContent.innerText = aiScript;
                scriptArea.classList.remove('hidden');
                scriptArea.scrollIntoView({ behavior: 'smooth', block: 'start' });
            } catch (error) { console.error(error); } finally {
                btn.disabled = false;
                btn.innerHTML = originalBtnText;
            }
        }

        // --- 3. Generate Image Prompt (Updated for Vietnamese Text Rendering) ---
        async function generateImagePrompt() {
            if (!currentHookText) return;
            let product = document.getElementById('productName').value.trim();
            const btn = document.getElementById('imgPromptBtn');
            const imageSection = document.getElementById('imageSection');
            const promptTextarea = document.getElementById('imagePromptText');

            const originalBtnText = btn.innerHTML;
            btn.disabled = true;
            btn.innerHTML = '<div class="loader inline-block mr-2"></div> Đang tạo prompt...';

            // Reset image result
            document.getElementById('imageResultContainer').classList.add('hidden');
            document.getElementById('generatedImage').classList.add('hidden');

            const prompt = `
                Dựa vào Tiêu đề Hook: "${currentHookText}" và Sản phẩm: "${product}".
                Hãy viết một mô tả (Prompt) chi tiết bằng TIẾNG VIỆT để vẽ ảnh Infographic khổ dọc 9:16.

                Yêu cầu đặc biệt về TEXT (CHỮ) trên ảnh:
                - Ảnh phải chứa chính xác dòng chữ: "${currentHookText}".
                - Yêu cầu AI vẽ chữ Tiếng Việt có dấu chuẩn xác (Chuẩn Tiếng Việt).
                - Font chữ phải to, đậm, Typography đẹp mắt, nằm ở vị trí dễ đọc (trung tâm hoặc 1/3 trên).
                - Text phải có độ tương phản cao so với nền.

                Yêu cầu về HÌNH ẢNH:
                - Hình ảnh minh họa phải gây sốc, tò mò hoặc ẩn dụ mạnh (Visual Metaphor).
                - Phong cách thiết kế hiện đại, màu sắc bắt mắt.

                Hãy viết Prompt hoàn chỉnh bằng Tiếng Việt.
            `;

            try {
                const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-09-2025:generateContent?key=${apiKey}`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ contents: [{ parts: [{ text: prompt }] }] })
                });

                const data = await response.json();
                const aiPrompt = data.candidates[0].content.parts[0].text.trim();

                promptTextarea.value = aiPrompt;
                imageSection.classList.remove('hidden');
                imageSection.scrollIntoView({ behavior: 'smooth', block: 'start' });

            } catch (error) { console.error(error); } finally {
                btn.disabled = false;
                btn.innerHTML = originalBtnText;
            }
        }

        // --- 4. Render Image ---
        async function renderImage() {
            const promptText = document.getElementById('imagePromptText').value;
            if (!promptText) return;

            const btn = document.getElementById('renderImageBtn');
            const resultContainer = document.getElementById('imageResultContainer');
            const imgEl = document.getElementById('generatedImage');
            const loader = document.getElementById('imageLoader');

            btn.disabled = true;
            btn.classList.add('opacity-50');
            resultContainer.classList.remove('hidden');
            loader.classList.remove('hidden');
            imgEl.classList.add('hidden');

            try {
                // Using Imagen with parameters
                const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/imagen-4.0-generate-001:predict?key=${apiKey}`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        instances: [{ prompt: promptText }],
                        parameters: { 
                            sampleCount: 1,
                            aspectRatio: "9:16" // Request Vertical Ratio
                        }
                    })
                });

                if (!response.ok) throw new Error('Image Gen Error');

                const data = await response.json();
                if (data.predictions && data.predictions[0] && data.predictions[0].bytesBase64Encoded) {
                    const base64 = data.predictions[0].bytesBase64Encoded;
                    imgEl.src = `data:image/png;base64,${base64}`;
                    imgEl.classList.remove('hidden');
                } else {
                    alert("Không thể tạo ảnh lúc này. Vui lòng thử lại sau.");
                }

            } catch (error) {
                console.error(error);
                alert("Lỗi khi kết nối với máy chủ vẽ tranh.");
            } finally {
                loader.classList.add('hidden');
                btn.disabled = false;
                btn.classList.remove('opacity-50');
            }
        }

        // --- Utils ---
        function copyCurrentHook() { copyToClipboard(currentHookText); }
        function copyScript() { copyToClipboard(document.getElementById('scriptContent').innerText); }
        function copyImagePrompt() { copyToClipboard(document.getElementById('imagePromptText').value); }

        function copyToClipboard(text) {
            if (!text) return;
            const el = document.createElement('textarea');
            el.value = text;
            document.body.appendChild(el);
            el.select();
            document.execCommand('copy');
            document.body.removeChild(el);
            showToast();
        }

        function showToast() {
            const toast = document.getElementById('toast');
            toast.classList.remove('translate-y-20', 'opacity-0');
            setTimeout(() => { toast.classList.add('translate-y-20', 'opacity-0'); }, 2000);
        }
    </script>
</body>
</html>

