                                            <RefreshCw className="animate-spin text-slate-400 mb-2" size={32}/>
                                            <span className="text-slate-500 text-sm font-medium">Đang vẽ tranh và viết chữ... (10-15s)</span>
                                        </div>
                                    ) : (
                                        generatedImage && (
                                            <img src={generatedImage} alt="AI Generated Infographic" className="max-w-full h-auto rounded shadow-lg max-h-[600px] animate-in zoom-in-95" />
                                        )
                                    )}
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {/* Tip */}
                {tip && (
                    <p className="text-center text-slate-400 text-xs mt-8 italic font-body">
                        {tip}
                    </p>
                )}
            </div>
        )}

      </div>

      {/* Toast Notification */}
      {showToast && (
        <div className="fixed bottom-8 left-1/2 transform -translate-x-1/2 bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl animate-in slide-in-from-bottom-2 fade-in z-50 flex items-center gap-2 whitespace-nowrap">
            <Check size={16} className="text-green-400"/>
            <span className="font-bold text-sm">Đã sao chép!</span>
        </div>
      )}
    </div>
  );
};

