      if (type === 'char') setCharImage(url);
      else setProdImage(url);
  };

  const generateBananaPrompt = async () => {
      setIsBananaGenerating(true);
      setBananaError("");
      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const prompt = `Create a stable diffusion prompt using trigger word "${bananaTriggerWord}".
          Style: ${bananaStylePreset}. Aspect Ratio: ${bananaAspectRatio}.
          Combine a character and a product context.`;
          const res = await ai.models.generateContent({model:'gemini-2.5-flash', contents: prompt});
          setGeneratedBananaPrompt(res.text || "");
          setShowResultModal(true);
      } catch(e) { setBananaError("Lỗi tạo prompt"); }
      setIsBananaGenerating(false);
  };

  const generateQuote = async () => {
      setIsQuoteLoading(true);
      const random = QUOTES_DATA[Math.floor(Math.random() * QUOTES_DATA.length)];
      setTimeout(() => { setCurrentQuote(random); setIsQuoteLoading(false); }, 500);
  };

  const handleSoraSeqImageUpload = async (file: File) => {
    try {
        const base64 = await fileToBase64(file);
        setSoraSeqImage({
            id: 'sora-ref', file, previewUrl: URL.createObjectURL(file), base64: base64.split(',')[1], mimeType: file.type
        });
    } catch (e) { console.error(e); }
  };

  const handleSoraSeqGeneratePrompt = async () => {
      if(!soraSeqDescription) return;
      setIsSoraSeqGeneratingPrompts(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Tạo chuỗi 3 prompt video liên tiếp (Sequence) cho Sora/Kling.
        Cốt truyện: ${soraSeqDescription}.
        Platform: ${soraSeqPlatform}. Style: ${soraSeqVideoStyle}.
        Output JSON: [{title, script_segment, visual_prompt}]`;
        const res = await ai.models.generateContent({model:'gemini-2.5-flash', contents: prompt});
        const jsonMatch = res.text?.match(/\[.*\]/s);
        setSoraSeqPromptsList(jsonMatch ? JSON.parse(jsonMatch[0]) : []);
        setShowResultModal(true);
      } catch(e) {}
      setIsSoraSeqGeneratingPrompts(false);
  };

  const handleGenerateGrokPrompt = async () => {
      if (!grokProductName) return;
      setIsGrokGenerating(true);
      setGrokResult("");
      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const prompt = `
          Đóng vai chuyên gia Prompt Engineering.
          Hãy viết một PROMPT (câu lệnh) chi tiết và tối ưu nhất để người dùng nhập vào AI (như Grok, ChatGPT, Claude) nhằm tạo ra một kịch bản video ngắn.

          Thông tin đầu vào cho Prompt này:
          - Sản phẩm: ${grokProductName}
          - Mô tả sản phẩm: ${grokProductDesc}
          - Nhân vật đóng vai: ${grokPersona}
          - Giọng điệu/Tone: ${grokTone}

          Yêu cầu đối với PROMPT bạn viết ra:
          1. Phải hướng dẫn AI đích (Grok) đóng vai nhân vật cực kỳ nhập tâm.
          2. Yêu cầu AI đích viết lời thoại độc thoại (monologue) bằng TIẾNG VIỆT tự nhiên, đời thường, không văn mẫu.
          3. Kịch bản phải ngắn gọn (30-60s), có mở đầu thu hút và kết thúc kêu gọi hành động.
          4. Chỉ trả về nội dung của Prompt đó (để người dùng copy).
          `;
          const res = await ai.models.generateContent({model:'gemini-2.5-flash', contents: prompt});
          setGrokResult(res.text || "Lỗi tạo prompt.");
      } catch (e) {
          console.error(e);
          setGrokResult("Không thể tạo prompt lúc này.");
      } finally {
          setIsGrokGenerating(false);
      }
  };

  const copyAllPrompts = () => { generatedPrompts.forEach(p => navigator.clipboard.writeText(p.prompt)); alert("Đã copy!"); };
  const copyBananaPrompt = () => { navigator.clipboard.writeText(generatedBananaPrompt); alert("Copied!"); };
  const copyAllVideoPrompts = () => { videoPrompts.forEach(p => navigator.clipboard.writeText(p.prompt)); alert("Copied!"); };
  const copyGrokPrompt = () => { navigator.clipboard.writeText(grokResult); alert("Đã copy Prompt cho Grok!"); };

  const renderResultModalContent = () => {
      switch (activeTab) {
          case 'prompts': return (
              <div className="space-y-6">
                  <div className="flex flex-col md:flex-row justify-between items-end mb-4"><div><h2 className="text-xl font-bold font-display text-slate-800 flex items-center gap-2"><ClipboardList className="text-orange-600" /> Bộ Prompt: {inputText}</h2><p className="text-slate-500 text-sm mt-1 font-body">Copy các prompt này để tạo ảnh infographic chuyên nghiệp.</p></div><button onClick={copyAllPrompts} className="px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900 transition flex items-center gap-2 text-sm font-medium shadow-lg"><Copy size={16} /> Copy Tất Cả</button></div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">{generatedPrompts.map((item) => (<PromptCard key={item.id} item={item} topic={inputText} />))}</div>
                  <div className="bg-gradient-to-br from-orange-600 to-amber-600 rounded-xl p-6 text-white mt-6 border border-orange-500 relative overflow-hidden"><div className="relative z-10"><div className="flex items-center gap-3 mb-4"><Mic size={24} className="text-yellow-200"/><h3 className="text-lg font-bold font-display">Kịch Bản Podcast (Voiceover)</h3></div>{!podcastScript && !isGeneratingPodcast && (<button onClick={generatePodcastScript} className="w-full py-2 bg-white text-orange-600 font-bold rounded-lg transition-all shadow-md flex items-center justify-center gap-2 hover:bg-orange-50"><Sparkles size={16}/> Tạo Kịch Bản Ngay</button>)}{isGeneratingPodcast && <div className="flex items-center justify-center py-4 text-orange-100"><RefreshCw className="animate-spin mr-2" /> Đang viết kịch bản...</div>}{podcastScript && (<div className="bg-black/20 p-4 rounded-xl border border-white/10 backdrop-blur-sm mt-2"><p className="text-sm leading-relaxed whitespace-pre-line text-white/90 font-body">{podcastScript}</p></div>)}</div></div>
              </div>
          );
          case 'video': return (
              <div className="space-y-6"><div className="flex justify-between items-center mb-4 lg:sticky lg:top-0 static bg-white z-10 py-2 border-b border-gray-50"><div><h3 className="font-bold font-display text-slate-800 text-lg">Kịch bản Video Nhân Vật (Veo)</h3></div><button onClick={copyAllVideoPrompts} className="px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-lg text-xs font-bold transition flex items-center gap-2"><Copy size={14}/> Copy All</button></div>{videoPrompts.map((scene, idx) => (<div key={idx} className="border border-gray-200 rounded-xl p-4 hover:border-amber-300 transition-colors bg-gray-50/50"><div className="flex justify-between items-start mb-2"><span className="bg-amber-100 text-amber-700 text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider">{scene.scene_name}</span><button onClick={() => navigator.clipboard.writeText(scene.prompt)} className="text-gray-400 hover:text-amber-600 p-1"><Copy size={16}/></button></div><div className="bg-orange-50 border border-orange-100 p-2 rounded mb-2 text-xs text-orange-900 italic font-body"><strong>Script/Mô tả:</strong> "{scene.description}"</div><div className="bg-white p-3 rounded-lg border border-gray-200 font-mono text-xs text-slate-600 leading-relaxed break-words">{scene.prompt}</div></div>))}</div>
