          );
          case 'sora_sequence': return (
              <div className="space-y-4">{soraSeqPromptsList.map((item, index) => (<div key={index} className="bg-white border border-gray-200 rounded-xl p-5 shadow-sm hover:shadow-md transition-all group relative hover:border-orange-200"><div className="flex justify-between items-start mb-3"><div className="flex items-center gap-3"><span className="bg-orange-100 text-orange-700 w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold shadow-sm border border-orange-200 shrink-0">{index + 1}</span><div><h4 className="font-bold font-display text-slate-700 text-sm">{item.title}</h4></div></div></div><div className="grid grid-cols-1 md:grid-cols-2 gap-4"><div className="bg-amber-50 p-3 rounded-lg border border-amber-100"><label className="text-[10px] font-bold text-amber-700 uppercase mb-1 block flex items-center"><Mic size={10} className="mr-1"/> Kịch bản</label><p className="text-sm font-body text-amber-900 italic">{item.script_segment}</p></div><div className="bg-slate-50 p-3 rounded-lg border border-slate-200"><label className="text-[10px] font-bold text-slate-500 uppercase mb-1 block flex items-center"><ScanEye size={10} className="mr-1"/> Visual Prompt</label><p className="text-xs text-slate-600 font-mono">{item.visual_prompt}</p></div></div></div>))}</div>
          );
          default: return null;
      }
