  return (
    <div className="lg:h-[calc(100vh-140px)] h-auto flex flex-col lg:flex-row font-body text-slate-800 bg-slate-50 border border-slate-200 rounded-2xl overflow-hidden shadow-sm">
      <div className="lg:w-64 w-full flex-none border-r border-slate-200 bg-white flex flex-col">
        <div className="p-4 border-b border-slate-100"><h2 className="text-lg font-bold font-display text-slate-800 flex items-center gap-2"><Lightbulb size={20} className="text-orange-600" /> Prompt AI</h2></div>
        <div className="flex-1 lg:overflow-y-auto p-2 space-y-1">
            {TABS.map((tab) => { const Icon = tab.icon; return (<button key={tab.id} onClick={() => setActiveTab(tab.id)} className={`w-full flex items-center gap-3 px-3 py-3 rounded-lg text-sm font-display font-semibold transition-all ${activeTab === tab.id ? `${tab.colorClass} bg-slate-50 shadow-sm ring-1 ring-slate-100` : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}`}><Icon size={18} />{tab.label}</button>)})}
        </div>
