            <div className="animate-in fade-in duration-300">
                <div className="bg-white rounded-2xl shadow-sm p-4 border border-orange-50 flex flex-col gap-4">
                  <div><label className="block text-xs font-bold font-display text-slate-600 mb-2 uppercase tracking-wider">1. Chủ đề & Bối cảnh</label><div className="flex flex-wrap gap-1.5 mb-2">{PROMPT_TOPICS.map(topic => (<button key={topic} onClick={() => setInputText(topic)} className="px-2 py-1 rounded bg-slate-100 text-slate-600 text-[10px] font-semibold hover:bg-orange-100 hover:text-orange-600 transition-colors border border-transparent hover:border-orange-200">{topic}</button>))}</div><div className="flex items-center gap-2 mb-2"><input type="text" value={inputText} onChange={(e) => setInputText(e.target.value)} placeholder="Nhập chủ đề..." className="flex-1 p-2.5 border border-slate-200 rounded-lg text-sm focus:border-orange-500 focus:ring-2 focus:ring-orange-100 outline-none font-body" /><button onClick={handleSuggestIdea} disabled={isSuggestingIdea} className="bg-orange-100 hover:bg-orange-200 text-orange-700 p-2.5 rounded-lg font-bold flex items-center gap-2 text-xs" title="AI Gợi ý">{isSuggestingIdea ? <RefreshCw className="animate-spin w-4 h-4"/> : <Lightbulb className="w-4 h-4"/>} Gợi ý</button></div><textarea value={description} onChange={(e) => setDescription(e.target.value)} placeholder="Mô tả chi tiết..." className="w-full p-2.5 border border-slate-200 rounded-lg text-xs h-16 resize-none focus:border-orange-500 focus:ring-2 focus:ring-orange-100 outline-none font-body"/></div>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-3"><div className="border rounded-xl p-3 bg-slate-50"><label className="block text-xs font-bold font-display text-slate-600 mb-2 uppercase">2. Phong cách</label><div className="space-y-1 max-h-32 overflow-y-auto custom-scrollbar pr-1">{styles.map(s => <button key={s.id} onClick={() => setSelectedStyle(s.id)} className={`w-full text-left p-2 rounded-lg text-xs border ${selectedStyle === s.id ? 'border-orange-500 bg-white text-orange-700 shadow-sm' : 'border-transparent hover:bg-white text-slate-600'}`}>{s.name}</button>)}</div></div></div>
                  <button onClick={generatePrompts} disabled={isGenerating || !inputText} className={`w-full py-3 rounded-xl font-bold font-display text-white shadow-md flex items-center justify-center gap-2 transition-all mt-auto ${isGenerating || !inputText ? 'bg-slate-300' : 'bg-gradient-to-r from-orange-600 to-amber-600 hover:shadow-orange-200'}`}>{isGenerating ? <RefreshCw className="animate-spin w-5 h-5" /> : <Sparkles className="w-5 h-5" />} {isGenerating ? 'Đang tạo...' : 'Tạo Prompt Ngay'}</button>
                </div>
            </div>
            )}

            {activeTab === 'video' && (
            <div className="animate-in fade-in duration-300 space-y-4">
               <div className="bg-white rounded-2xl shadow-sm p-4 border border-amber-100 flex flex-col md:flex-row gap-6">
                  <div className="w-full md:w-1/3 space-y-3">
                     <label className="text-xs font-bold font-display text-slate-600 uppercase">1. Nhân vật mẫu (Reference)</label>
                     <UploadBox id="veo-upload" label="Ảnh nhân vật" image={veoReferenceImage} onUpload={handleVeoImageUpload} onRemove={() => setVeoReferenceImage(null)} heightClass="h-48" />
                     <button onClick={generateVeoDescriptionFromImage} disabled={!veoReferenceImage || isVeoDescGenerating} className="w-full py-2 bg-amber-100 text-amber-800 rounded-lg text-xs font-bold flex items-center justify-center gap-2 hover:bg-amber-200 transition">{isVeoDescGenerating ? <RefreshCw className="animate-spin" size={14}/> : <ScanEye size={14}/>} Phân tích nhân vật</button>
                  </div>
                  <div className="flex-1 space-y-4">
                      <div>
                         <label className="text-xs font-bold font-display text-slate-600 uppercase mb-2 block">2. Mô tả bối cảnh & sản phẩm</label>
                         <textarea value={videoProductDesc} onChange={(e) => setVideoProductDesc(e.target.value)} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm h-32 resize-none outline-none focus:border-amber-400 font-body" placeholder="Mô tả nhân vật đang làm gì, bối cảnh ở đâu, sản phẩm là gì..." />
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                          <div>
                             <label className="text-xs font-bold font-display text-slate-600 uppercase mb-1 block">Phong cách Video</label>
                             <select value={videoStyle} onChange={(e) => setVideoStyle(e.target.value)} className="w-full p-2 border border-slate-200 rounded-lg text-xs outline-none bg-white font-body">
                                {videoStyles.map(s => <option key={s} value={s}>{s}</option>)}
                             </select>
                          </div>
                          <div>
                             <label className="text-xs font-bold font-display text-slate-600 uppercase mb-1 block">Thời lượng</label>
                             <select value={videoTotalDuration} onChange={(e) => setVideoTotalDuration(e.target.value)} className="w-full p-2 border border-slate-200 rounded-lg text-xs outline-none bg-white font-body">
                                {veoClipDurations.map(d => <option key={d} value={d}>{d}</option>)}
                             </select>
                          </div>
                      </div>
                      <button onClick={generateVideoPrompts} disabled={isVideoGenerating || !videoProductDesc} className="w-full py-3 bg-gradient-to-r from-amber-600 to-orange-500 text-white font-bold rounded-xl shadow-md hover:shadow-lg transition-all flex items-center justify-center gap-2">{isVideoGenerating ? <RefreshCw className="animate-spin"/> : <Video/>} Tạo Kịch Bản Video</button>
                  </div>
               </div>
            </div>
            )}

            {activeTab === 'grok_ad' && (
            <div className="animate-in fade-in duration-300 space-y-4">
                <div className="bg-white rounded-2xl shadow-sm p-4 border border-cyan-100 flex flex-col gap-6">
                    <div>
                        <div className="flex items-center gap-2 mb-4">
                            <Bot className="text-cyan-600 w-6 h-6" />
                            <div>
                                <h3 className="font-bold font-display text-slate-800 text-lg">Grok Ad Speaker</h3>
                                <p className="text-slate-500 text-xs font-body">Tạo prompt cho nhân vật nói quảng cáo (Grok/ChatGPT/Claude)</p>
                            </div>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                            <div>
                                <label className="text-xs font-bold font-display text-slate-600 uppercase mb-1 block">Tên Sản Phẩm</label>
                                <input type="text" value={grokProductName} onChange={(e) => setGrokProductName(e.target.value)} className="w-full p-3 border border-slate-200 rounded-lg text-sm font-body outline-none focus:ring-2 focus:ring-cyan-400" placeholder="VD: Nước hoa Charme..." />
                            </div>
                            <div>
                                <label className="text-xs font-bold font-display text-slate-600 uppercase mb-1 block">Nhân vật (Persona)</label>
                                <select value={grokPersona} onChange={(e) => setGrokPersona(e.target.value)} className="w-full p-3 border border-slate-200 rounded-lg text-sm font-body outline-none bg-white">
                                    {grokPersonas.map(p => <option key={p} value={p}>{p}</option>)}
                                </select>
                            </div>
                        </div>
                        <div className="mb-4">
                            <label className="text-xs font-bold font-display text-slate-600 uppercase mb-1 block">Mô tả sản phẩm</label>
                            <textarea value={grokProductDesc} onChange={(e) => setGrokProductDesc(e.target.value)} className="w-full p-3 border border-slate-200 rounded-lg text-sm h-24 resize-none font-body outline-none focus:ring-2 focus:ring-cyan-400" placeholder="Công dụng, thành phần, ưu điểm nổi bật..." />
                        </div>
                        <div className="mb-6">
                            <label className="text-xs font-bold font-display text-slate-600 uppercase mb-1 block">Giọng điệu (Tone)</label>
                            <div className="flex flex-wrap gap-2">
                                {grokTones.map(t => (
                                    <button key={t} onClick={() => setGrokTone(t)} className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${grokTone === t ? 'bg-cyan-50 border-cyan-500 text-cyan-700' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}`}>
                                        {t}
                                    </button>
