                                <button onClick={copyGrokPrompt} className="text-xs font-bold text-cyan-600 hover:text-cyan-700 flex items-center gap-1 bg-cyan-50 px-2 py-1 rounded"><Copy size={12}/> Copy</button>
                            </div>
                            <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
                                <p className="text-xs font-mono text-slate-700 leading-relaxed whitespace-pre-wrap">{grokResult}</p>
                            </div>
                        </div>
                    )}
                </div>
            </div>
            )}

            {activeTab === 'sora_sequence' && (
            <div className="animate-in fade-in duration-300 space-y-4">
                 <div className="bg-white rounded-2xl shadow-sm p-4 border border-orange-100 flex flex-col md:flex-row gap-6">
                    <div className="w-full md:w-1/3 space-y-3">
