                                <select value={soraSeqClipDuration} onChange={(e) => setSoraSeqClipDuration(e.target.value)} className="w-full p-2 border border-slate-200 rounded-lg text-xs font-body"><option value="5s">5s</option><option value="8s">8s</option><option value="10s">10s</option></select>
