                    <div className="flex justify-center gap-4 mb-6">
                         <button onClick={generateQuote} className="px-6 py-2 bg-slate-800 text-white rounded-full font-bold text-sm hover:bg-slate-900 transition flex items-center gap-2 shadow-lg"><RefreshCw size={14}/> Đổi câu khác</button>
