import React, { useState } from 'react';
import { Sparkles, Box, Upload, Download, RefreshCw, AlertCircle, Megaphone, Palette, Type, User, Video, Copy, Camera, Layout, Crop, Lightbulb } from 'lucide-react';
import { ProcessedImage } from '../types';
import { generateAdImage, generateMarketingImage, generateVideoPrompt } from '../services/geminiService';
import { ImageUploader } from './ImageUploader';
import { ASPECT_RATIOS } from '../constants';
import { PhotoConcept } from './PhotoConcept';

export const AIImageGenerator: React.FC = () => {
  const [mode, setMode] = useState<'poster' | 'marketing' | 'concept'>('poster');

  // Shared State
  const [productImage, setProductImage] = useState<ProcessedImage | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedAspectRatio, setSelectedAspectRatio] = useState(ASPECT_RATIOS[0].id); // Default 1:1

  // Poster Mode State
  const [logoImage, setLogoImage] = useState<ProcessedImage | null>(null);
  const [adPrompt, setAdPrompt] = useState('Ảnh quảng cáo, chất lượng cao, hiện đại');
  const [posterResult, setPosterResult] = useState<string | null>(null);

  // Marketing Mode State
  const [faceImage, setFaceImage] = useState<ProcessedImage | null>(null);
  const [productName, setProductName] = useState('');
  const [marketingFeedback, setMarketingFeedback] = useState('');
  const [marketingResult, setMarketingResult] = useState<string | null>(null);
  const [videoPrompt, setVideoPrompt] = useState<string>('');
  const [isVideoGenerating, setIsVideoGenerating] = useState(false);

  const processFile = (file: File): Promise<ProcessedImage> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        if (event.target?.result) {
            img.src = event.target.result as string;
            img.onload = () => {
              const canvas = document.createElement('canvas');
              const MAX_WIDTH = 1024; 
              const scaleSize = MAX_WIDTH / Math.max(img.width, MAX_WIDTH);
              canvas.width = img.width * scaleSize;
              canvas.height = img.height * scaleSize;
              const ctx = canvas.getContext('2d');
              if (ctx) {
                  ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
                  const dataUrl = canvas.toDataURL(file.type);
                  resolve({
                    preview: dataUrl,
                    base64: dataUrl.split(',')[1],
                    mimeType: file.type
                  });
              } else {
                  reject(new Error("Canvas context failed"));
              }
            };
            img.onerror = (e) => reject(e);
        }
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, setter: React.Dispatch<React.SetStateAction<ProcessedImage | null>>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith('image/')) {
        setError('Vui lòng chọn một file ảnh.');
        return;
    }

    try {
      setError(null);
      const processed = await processFile(file);
      setter(processed);
    } catch (err) {
      console.error(err);
      setError('Lỗi xử lý ảnh.');
    }
  };

  const handleGenerate = async () => {
    if (!productImage) {
      setError('Vui lòng tải lên ảnh sản phẩm.');
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
        if (mode === 'poster') {
            setPosterResult(null);
            const result = await generateAdImage(productImage, logoImage, adPrompt, selectedAspectRatio);
            setPosterResult(result);
        } else {
            if (!productName) { throw new Error('Vui lòng nhập tên sản phẩm.'); }
            setMarketingResult(null);
            setVideoPrompt('');
            const result = await generateMarketingImage(productImage, faceImage, productName, marketingFeedback, selectedAspectRatio);
            setMarketingResult(result);
        }
    } catch (err: any) {
        console.error('Lỗi gọi API:', err);
        setError(`Lỗi tạo ảnh: ${err.message}`);
    } finally {
        setIsLoading(false);
    }
  };

  const handleGenerateVideoPrompt = async () => {
      if (!marketingResult || !productName) return;
      setIsVideoGenerating(true);
      try {
          const imageDesc = `Ảnh marketing cho ${productName}. ${marketingFeedback}`;
          const prompt = await generateVideoPrompt(productName, marketingFeedback, imageDesc);
          setVideoPrompt(prompt);
      } catch (err: any) {
          setError(err.message);
      } finally {
          setIsVideoGenerating(false);
      }
  };

  const downloadImage = (url: string | null) => {
    if (url) {
      const link = document.createElement('a');
      link.href = url;
      link.download = `ai-gen-${mode}-${Date.now()}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  return (
    <div className="lg:h-full h-auto flex flex-col bg-white">
      {/* Mode Switcher */}
      <div className="flex-none p-4 bg-orange-50 border-b border-orange-100 flex justify-center">
          <div className="bg-white p-1 rounded-xl border border-orange-200 shadow-sm flex gap-1 overflow-x-auto custom-scrollbar">
              <button 
                  onClick={() => setMode('poster')}
                  className={`px-6 py-2.5 rounded-lg text-sm font-display font-bold flex items-center gap-2 transition-all whitespace-nowrap ${mode === 'poster' ? 'bg-orange-500 text-white shadow-md' : 'text-gray-500 hover:bg-orange-50'}`}
              >
                  <Megaphone size={16} /> Poster Quảng Cáo
              </button>
              <button 
                  onClick={() => setMode('marketing')}
                  className={`px-6 py-2.5 rounded-lg text-sm font-display font-bold flex items-center gap-2 transition-all whitespace-nowrap ${mode === 'marketing' ? 'bg-amber-500 text-white shadow-md' : 'text-gray-500 hover:bg-amber-50'}`}
              >
                  <Camera size={16} /> Ảnh Lifestyle & Video
              </button>
              <button 
                  onClick={() => setMode('concept')}
                  className={`px-6 py-2.5 rounded-lg text-sm font-display font-bold flex items-center gap-2 transition-all whitespace-nowrap ${mode === 'concept' ? 'bg-amber-600 text-white shadow-md' : 'text-gray-500 hover:bg-amber-50'}`}
              >
                  <Lightbulb size={16} /> Photo Concept & Remix
              </button>
          </div>
      </div>

      {mode === 'concept' ? (
        <PhotoConcept />
      ) : (
        <div className="flex-1 min-h-0 grid grid-cols-1 lg:grid-cols-12 lg:divide-x lg:divide-y-0 divide-y divide-gray-200 h-auto">

          {/* COLUMN 1: UPLOADS */}
          <div className="lg:col-span-3 p-4 flex flex-col gap-4 lg:overflow-y-auto h-auto custom-scrollbar bg-slate-50/50">
              <div className="flex items-center gap-2 mb-1">
                  <span className="bg-orange-100 text-orange-700 w-6 h-6 rounded-full flex items-center justify-center text-xs font-display font-bold">1</span>
                  <h3 className="font-display font-bold text-gray-700 text-sm uppercase">Tài Nguyên</h3>
              </div>

              <ImageUploader 
                  label="Ảnh Sản Phẩm (Bắt buộc)" 
                  icon={<Box size={14} className="text-orange-600" />}
                  image={productImage}
                  onUpload={(e) => handleFileUpload(e, setProductImage)}
                  onRemove={() => setProductImage(null)}
                  colorClass="text-orange-600"
                  bgColorClass="bg-orange-50"
                  borderColorClass="border-orange-400"
                  heightClass="h-40"
              />

              {mode === 'poster' ? (
                  <div className="animate-in fade-in slide-in-from-left-2">
                      <ImageUploader 
                          label="Logo (Tùy chọn)" 
                          icon={<Upload size={14} className="text-amber-600" />}
                          image={logoImage}
                          onUpload={(e) => handleFileUpload(e, setLogoImage)}
                          onRemove={() => setLogoImage(null)}
                          colorClass="text-amber-600"
                          bgColorClass="bg-amber-50"
                          borderColorClass="border-amber-400"
                          heightClass="h-32"
                      />
                       <p className="text-[10px] text-gray-500 italic mt-1 font-body">*Logo sẽ được chèn tự động vào góc ảnh.</p>
                  </div>
              ) : (
                  <div className="animate-in fade-in slide-in-from-left-2">
                      <ImageUploader 
                          label="Gương Mặt Mẫu (Tùy chọn)" 
                          icon={<User size={14} className="text-amber-600" />}
                          image={faceImage}
                          onUpload={(e) => handleFileUpload(e, setFaceImage)}
                          onRemove={() => setFaceImage(null)}
                          colorClass="text-amber-600"
                          bgColorClass="bg-amber-50"
                          borderColorClass="border-amber-400"
                          heightClass="h-40"
                      />
                      <p className="text-[10px] text-gray-500 italic mt-1 font-body">*AI sẽ ghép mặt này vào người mẫu trong ảnh.</p>
                  </div>
              )}
          </div>

          {/* COLUMN 2: CONFIG */}
          <div className="lg:col-span-5 p-4 lg:overflow-y-auto h-auto custom-scrollbar bg-white">
              <div className="flex items-center gap-2 mb-4 lg:sticky lg:top-0 static bg-white z-10 py-1">
                  <span className="bg-orange-100 text-orange-700 w-6 h-6 rounded-full flex items-center justify-center text-xs font-display font-bold">2</span>
                  <h3 className="font-display font-bold text-gray-700 text-sm uppercase">
                      {mode === 'poster' ? 'Cấu Hình Poster' : 'Cấu Hình Marketing'}
                  </h3>
              </div>

              <div className="space-y-6">
                   {/* Aspect Ratio Selector */}
                   <div className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm animate-in fade-in">
                      <label className="flex items-center gap-1.5 font-display font-bold text-gray-600 text-xs uppercase mb-3">
                          <Crop size={14}/> Chọn Tỷ Lệ Khung Hình
                      </label>
                      <div className="grid grid-cols-3 gap-2">
                          {ASPECT_RATIOS.map((item) => (
                              <button
                                  key={item.id}
                                  onClick={() => setSelectedAspectRatio(item.id)}
                                  className={`p-2 rounded-lg text-xs font-medium border transition-all flex flex-col items-center justify-center gap-1 h-14
                                  ${selectedAspectRatio === item.id 
                                      ? 'bg-orange-50 border-orange-500 text-orange-700 shadow-sm' 
                                      : 'border-gray-200 text-gray-500 hover:border-orange-300 hover:bg-gray-50'}`}
                              >
                                  <span className="font-display">{item.label.split(' ')[0]}</span>
                                  <span className="text-[10px] opacity-70">{item.id}</span>
                              </button>
                          ))}
                      </div>
                  </div>

                  {mode === 'poster' ? (
                      <div className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm animate-in fade-in">
                          <label className="flex items-center gap-1.5 font-display font-bold text-gray-600 text-xs uppercase mb-3">
                              <Palette size={14}/> Phong Cách Thiết Kế
                          </label>
                          <textarea
                              rows={4}
                              className="w-full p-3 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-orange-500 outline-none resize-none bg-gray-50 font-body"
                              placeholder="Mô tả: Phong cách Cyberpunk, nền tối sang trọng, ánh sáng Neon..."
                              value={adPrompt}
                              onChange={(e) => setAdPrompt(e.target.value)}
                          />
                          <div className="mt-3 flex gap-2 flex-wrap">
                              {['Tối giản (Minimalist)', 'Sang trọng (Luxury)', 'Thiên nhiên (Eco)', 'Công nghệ (Tech)'].map(tag => (
                                  <button key={tag} onClick={() => setAdPrompt(tag)} className="px-2 py-1 bg-gray-100 hover:bg-gray-200 text-gray-600 text-[10px] rounded-md transition-colors font-body">{tag}</button>
                              ))}
                          </div>
                      </div>
                  ) : (
                      <div className="space-y-4 animate-in fade-in">
                          <div>
                              <label className="text-xs font-display font-bold text-gray-600 mb-1 block uppercase">Tên Sản Phẩm *</label>
                              <input 
                                  type="text" 
                                  className="w-full p-3 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-amber-500 outline-none font-body"
                                  placeholder="Ví dụ: Nước hoa Charme..."
                                  value={productName}
                                  onChange={e => setProductName(e.target.value)}
                              />
                          </div>
                           <div>
                              <label className="text-xs font-display font-bold text-gray-600 mb-1 block uppercase">Bối cảnh & Yêu cầu (USP)</label>
