                                  className="w-full p-3 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-amber-500 outline-none resize-none font-body"
                                  placeholder="Mô tả bối cảnh muốn tạo (ví dụ: trên bàn làm việc, ngoài bãi biển). Điểm nổi bật cần nhấn mạnh..."
                                  value={marketingFeedback}
                                  onChange={e => setMarketingFeedback(e.target.value)}
                              />
                          </div>
                      </div>
                  )}
              </div>
          </div>

          {/* COLUMN 3: RESULT - UPDATED TO ALLOW SCROLLING */}
