                </div>
            )}

            <div className="w-full bg-gray-200/50 rounded-2xl border-2 border-dashed border-gray-300 relative overflow-hidden group min-h-[500px] flex flex-col shrink-0">
                 {isLoading && (
                    <div className="absolute inset-0 bg-white/80 backdrop-blur-[2px] z-10 flex flex-col items-center justify-center p-4">
                        <div className={`w-8 h-8 border-4 rounded-full animate-spin mb-3 ${mode === 'poster' ? 'border-orange-200 border-t-orange-600' : 'border-amber-200 border-t-amber-600'}`}></div>
                        <p className={`font-bold animate-pulse text-xs font-body ${mode === 'poster' ? 'text-orange-600' : 'text-amber-600'}`}>AI đang thiết kế...</p>
                    </div>
                )}

                {(mode === 'poster' ? posterResult : marketingResult) ? (
                    <div className="relative w-full p-2">
                        {/* Display full height image to allow scrolling */}
                        <img 
                          src={(mode === 'poster' ? posterResult : marketingResult)!} 
                          alt="Kết Quả" 
                          className="w-full h-auto rounded-lg shadow-xl" 
                        />
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-center text-gray-400 p-6">
                        {mode === 'poster' ? <Megaphone size={32} className="mx-auto mb-2 opacity-50" /> : <Camera size={32} className="mx-auto mb-2 opacity-50" />}
                        <p className="text-sm font-medium font-body">Chưa Có Ảnh</p>
                        <p className="text-xs mt-1 font-body">Kết quả sẽ hiển thị ở đây</p>
                    </div>
                )}
            </div>

            {/* Video Prompt Generation Section (Only for Marketing Mode) */}
            {mode === 'marketing' && marketingResult && (
               <div className="mt-2 border-t pt-4 border-gray-200 animate-in fade-in slide-in-from-bottom-2 shrink-0">
                  <button 
                      onClick={handleGenerateVideoPrompt}
                      disabled={isVideoGenerating}
                      className="w-full py-2 bg-amber-100 text-amber-700 font-display font-bold rounded-lg hover:bg-amber-200 transition flex items-center justify-center gap-2 text-sm"
                  >
                      {isVideoGenerating ? <RefreshCw className="animate-spin" size={14}/> : <Video size={14}/>}
                      Tạo Prompt Video (Từ Ảnh Này)
                  </button>

                  {videoPrompt && (
                      <div className="mt-3 bg-white border border-amber-200 rounded-xl p-3 relative group shadow-sm">
                          <label className="text-[10px] font-bold text-amber-500 uppercase mb-1 block">Prompt Video (Copy & Paste vào Veo/Sora)</label>
                          <p className="text-xs text-gray-700 whitespace-pre-wrap max-h-40 overflow-y-auto custom-scrollbar font-body">{videoPrompt}</p>
                          <button 
                              onClick={() => {navigator.clipboard.writeText(videoPrompt); alert('Copied!');}}
                              className="absolute top-2 right-2 p-1.5 bg-gray-100 hover:bg-white rounded text-gray-500 hover:text-amber-600 transition"
                              title="Copy Prompt"
                          >
                              <Copy size={12}/>
                          </button>
                      </div>
                  )}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

