export const VirtualTryOn: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'preset' | 'upload'>('preset');
  const [modelImage, setModelImage] = useState<ImageAsset | null>(null);
  const [productImage, setProductImage] = useState<ImageAsset | null>(null);

  const categories = Object.keys(OUTFIT_DATABASE);
  const [selectedCategory, setSelectedCategory] = useState(categories[0]);
  const [selectedOutfit, setSelectedOutfit] = useState("");
  const [searchTerm, setSearchTerm] = useState("");
  const [customDescription, setCustomDescription] = useState('');

  const [selectedBackdrop, setSelectedBackdrop] = useState(BACKDROPS[0]);
  const [lighting, setLighting] = useState(LIGHTING_OPTIONS[0]);
  const [filter, setFilter] = useState(FILTER_OPTIONS[0]);
  const [beautyOptions, setBeautyOptions] = useState<string[]>([]);
  const [selectedAspectRatio, setSelectedAspectRatio] = useState(ASPECT_RATIOS[1].id); // Default 3:4

  const [resultImage, setResultImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  const resultRef = useRef<HTMLDivElement>(null);

  // Filter styles based on search term
  const filteredStyles = useMemo(() => {
    const styles = OUTFIT_DATABASE[selectedCategory] || [];
    if (!searchTerm) return styles;
    return styles.filter(style => style.toLowerCase().includes(searchTerm.toLowerCase()));
  }, [selectedCategory, searchTerm]);

  useEffect(() => {
    if (resultImage && window.innerWidth < 1024 && resultRef.current) {
        resultRef.current.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  }, [resultImage]);

  const handleModelUpload = async (file: File) => {
    try {
      const base64 = await fileToBase64(file);
      const mimeType = getMimeType(file);
      setModelImage({
        id: Math.random().toString(36).substr(2, 9),
        file,
        previewUrl: URL.createObjectURL(file),
        base64,
        mimeType
      });
    } catch (e) {
      console.error("Upload failed", e);
      alert("Lỗi tải ảnh");
    }
  };

  const handleProductUpload = async (file: File) => {
    try {
      const base64 = await fileToBase64(file);
      const mimeType = getMimeType(file);
      setProductImage({
        id: Math.random().toString(36).substr(2, 9),
        file,
        previewUrl: URL.createObjectURL(file),
        base64,
        mimeType
      });
    } catch (e) {
      console.error("Upload failed", e);
      alert("Lỗi tải ảnh");
    }
  };

  const toggleBeautyOption = (option: string) => {
    setBeautyOptions(prev => 
      prev.includes(option) ? prev.filter(o => o !== option) : [...prev, option]
    );
  };

  const handleGenerate = async () => {
    if (!modelImage) return;
    if (activeTab === 'upload' && !productImage) {
        alert("Vui lòng tải lên ảnh trang phục mẫu.");
        return;
    }

    setIsGenerating(true);
    setResultImage(null);

    try {
      const prodImg = activeTab === 'upload' ? productImage : null;
      // If preset tab: use custom description OR selected outfit from database
      const desc = activeTab === 'preset' 
        ? (customDescription || selectedOutfit || "Fashionable outfit matching the person's style") 
        : "Match the clothing in the reference image";

      const imageUrl = await generateVirtualTryOn(
        modelImage, 
        desc, 
        lighting, 
        filter, 
        beautyOptions,
        selectedBackdrop,
        prodImg,
        selectedAspectRatio
      );
      setResultImage(imageUrl);
    } catch (e) {
      console.error(e);
      alert("Không thể thực hiện thay đồ. Vui lòng thử lại.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    if (resultImage) {
      const link = document.createElement('a');
      link.href = resultImage;
      link.download = `virtual-try-on-${Date.now()}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  return (
    <div className="lg:h-full h-auto flex flex-col animate-fade-in lg:pb-0 lg:overflow-hidden">
      <div className="bg-white p-4 border-b border-gray-200 shrink-0">
          <div className="flex items-center gap-3">
             <div className="p-2 bg-orange-100 rounded-xl text-orange-600">
               <Shirt size={20} />
             </div>
             <div>
               <h3 className="font-display font-bold text-gray-800 text-lg">Phòng Thử Đồ Ảo</h3>
               <p className="text-xs text-gray-500 font-body">Thay trang phục & Chỉnh sửa ảnh Beauty</p>
             </div>
          </div>
      </div>

