              <div className="space-y-6 flex-1">
                <div>
                   <label className="block text-sm font-display font-bold text-gray-700 mb-2 flex items-center">
                      <User size={16} className="mr-2 text-orange-500"/> 1. Ảnh Người Mẫu (Bắt buộc)
                   </label>
                   <UploadBox 
                     id="model-upload" 
                     label="Tải ảnh người muốn thay đồ" 
                     image={modelImage} 
                     onUpload={handleModelUpload} 
                     onRemove={() => setModelImage(null)}
                     heightClass="h-40"
                   />
                </div>

                <div className="bg-gray-100 p-1 rounded-xl flex">
                    <button
                        onClick={() => setActiveTab('preset')}
                        className={`flex-1 py-2 rounded-lg text-sm font-display font-bold transition-all ${activeTab === 'preset' ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                    >
                        Chọn Mẫu Có Sẵn
                    </button>
                    <button
                        onClick={() => setActiveTab('upload')}
                        className={`flex-1 py-2 rounded-lg text-sm font-display font-bold transition-all ${activeTab === 'upload' ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                    >
                        Tải Ảnh Đồ Mới
                    </button>
                </div>

                {activeTab === 'preset' ? (
                    <div className="space-y-4 animate-fade-in">
                        <div>
                            <label className="block text-sm font-display font-bold text-gray-700 mb-2 flex items-center">
                                <Package size={16} className="mr-2 text-orange-500"/> 2. Chọn Danh Mục & Phong Cách
                            </label>

                            {/* Category Selector */}
                            <select 
                                value={selectedCategory} 
                                onChange={(e) => { setSelectedCategory(e.target.value); setSearchTerm(""); }}
                                className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-400 outline-none mb-3 text-sm font-bold text-gray-700 font-body"
                            >
                                {categories.map((cat, idx) => (
                                <option key={idx} value={cat}>{cat}</option>
                                ))}
                            </select>

                            {/* Search Bar for Styles */}
                            <div className="relative mb-3">
                                <Search className="absolute left-3 top-3 text-gray-400 w-4 h-4" />
                                <input 
