                                />
                            </div>

                            {/* Scrollable Style Grid */}
                            <div className="border border-gray-200 rounded-xl bg-gray-50 p-2 h-48 overflow-y-auto custom-scrollbar">
                                <div className="grid grid-cols-1 gap-2">
                                    {filteredStyles.map((style, idx) => (
                                        <button
