                                            </div>
                                            <span className="leading-snug">{style}</span>
                                        </button>
                                    ))}
                                    {filteredStyles.length === 0 && (
                                        <p className="text-center text-gray-400 text-xs py-4">Không tìm thấy phong cách nào.</p>
                                    )}
                                </div>
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-display font-bold text-gray-700 mb-2">Prompt (Mô tả trang phục):</label>
                            <textarea 
                                value={customDescription}
                                onChange={(e) => setCustomDescription(e.target.value)}
                                placeholder="Chọn phong cách ở trên hoặc tự viết mô tả tại đây..."
                                className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-400 outline-none text-sm h-20 resize-none font-body text-gray-700"
                            />
                        </div>
                    </div>
                ) : (
