                            <Upload size={16} className="mr-2 text-orange-500"/> 2. Tải Ảnh Sản Phẩm Mẫu
                        </label>
                        <UploadBox 
                            id="product-upload" 
                            label="Tải ảnh quần áo/váy mẫu" 
                            image={productImage} 
                            onUpload={handleProductUpload} 
                            onRemove={() => setProductImage(null)}
                            heightClass="h-40"
                        />
                        <p className="text-xs text-gray-500 mt-2 italic font-body">
                            *AI sẽ tự động mặc trang phục từ ảnh này sang cho người mẫu. Nên dùng ảnh sản phẩm trải phẳng hoặc ảnh manocanh.
                        </p>
                    </div>
                )}

                {/* NEW BACKDROP SELECTOR */}
