  // Tabs update - Added 'vision_scanner'
  const [activeTab, setActiveTab] = useState<'studio' | 'ai_image_generator' | 'content_genius' | 'text_to_speech' | 'prompt_builder' | 'sora_prompt_gen' | 'hook_generator' | 'vision_scanner'>('studio');

