                    onClick={() => setSubTab('hook')}
                    className={`px-6 py-2.5 rounded-lg text-sm font-display font-bold flex items-center gap-2 transition-all whitespace-nowrap ${subTab === 'hook' ? 'bg-orange-500 text-white shadow-md' : 'text-gray-500 hover:bg-orange-50'}`}
                >
                    <Bolt size={16} /> Hook Video Viral
                </button>
                <button 
                    onClick={() => setSubTab('content')}
