                <div className="bg-white rounded-3xl shadow-lg shadow-orange-100/50 p-6 mb-8 border border-orange-100">
                    <div className="grid grid-cols-1 gap-5">
                        <div>
                            <label className="block text-xs font-bold font-display text-slate-500 uppercase tracking-wide mb-1">Tên Sản Phẩm / Dịch Vụ</label>
