Trong Modul Hook Video thêm modul mới với code sau 
import React, { useState, useEffect, useCallback } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { 
  Copy, RefreshCw, AlertTriangle, MessageCircle, Share2, 
  ThumbsUp, Globe, MoreHorizontal, Sparkles, Zap, 
  Check, Layers, Laugh, Skull, Eye, HeartHandshake, ShieldAlert, Loader2, ArrowDown
} from 'lucide-react';
import { KOL_TEMPLATES } from '../constants';
import { KolInputState, KolStyleKey } from '../types';

export const KolContentGenerator: React.FC = () => {
  const [inputs, setInputs] = useState<KolInputState>({
    kolName: '',
    productName: '',
    productDescription: '',
    benefit: '',
    context: '',
    link: '',
    style: 'kol_boc_phot'
  });

  const [generatedPost, setGeneratedPost] = useState('');
  const [generatedComment, setGeneratedComment] = useState('');

  const [isPostCopied, setIsPostCopied] = useState(false);
  const [isCommentCopied, setIsCommentCopied] = useState(false);
  const [isAllCopied, setIsAllCopied] = useState(false);

  const [isGenerating, setIsGenerating] = useState(false);
  const [isSuggestingBenefit, setIsSuggestingBenefit] = useState(false);
  const [useAI, setUseAI] = useState(true);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setInputs(prev => ({
      ...prev,
      [e.target.name]: e.target.value
    }));
  };

  const setStyle = (style: KolStyleKey) => {
    setInputs(prev => ({ ...prev, style }));
  };

  // Helper to generate content from static templates (Fallback)
  const generateStaticContent = useCallback(() => {
    const styleTemplates = KOL_TEMPLATES[inputs.style];
    const randomTemplate = styleTemplates[Math.floor(Math.random() * styleTemplates.length)];

    let post = randomTemplate.post;
    let comment = randomTemplate.comment;

    const productNameNoSpace = inputs.productName.replace(/\s+/g, '') || "Sanpham";
    const replaceAll = (str: string, find: string, replace: string) => str.split(find).join(replace);

    const kolName = inputs.kolName || "[Tên Idol/KOL]";
    const productName = inputs.productName || "[Tên Sản Phẩm]";
    const productNameKey = inputs.productName ? productNameNoSpace : "Sanpham";
    const benefit = inputs.benefit || "[Điểm mạnh/Lợi ích]";
    const link = inputs.link || "[Link mua hàng]";

    post = replaceAll(post, '{kolName}', kolName);
    post = replaceAll(post, '{productName}', productName);
    post = replaceAll(post, '{productNameNoSpace}', productNameKey);
    post = replaceAll(post, '{benefit}', benefit);
    post = replaceAll(post, '{link}', link);

    comment = replaceAll(comment, '{kolName}', kolName);
    comment = replaceAll(comment, '{productName}', productName);
    comment = replaceAll(comment, '{productNameNoSpace}', productNameKey);
    comment = replaceAll(comment, '{benefit}', benefit);
    comment = replaceAll(comment, '{link}', link);

    setGeneratedPost(post);
    setGeneratedComment(comment);
  }, [inputs]);

  // Suggest Benefits based on Product Name
  const handleSuggestBenefits = async () => {
    if (!inputs.productName && !inputs.productDescription) {
      alert("Vui lòng nhập Tên sản phẩm hoặc Mô tả sản phẩm để AI gợi ý!");
      return;
    }

    if (!process.env.API_KEY) {
      alert("Chưa cấu hình API Key.");
      return;
    }

    setIsSuggestingBenefit(true);
    try {
       const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
       const prompt = `
         Dựa trên thông tin sau:
         - Tên sản phẩm: "${inputs.productName}"
         - Mô tả sơ bộ: "${inputs.productDescription}"

         Hãy phân tích và liệt kê 5-7 "Điểm mạnh nhất/USP" (Unique Selling Point) của sản phẩm này dưới dạng từ khóa ngắn gọn, hấp dẫn để dùng viết quảng cáo.
         Chỉ trả về kết quả dưới dạng một đoạn văn, các ý cách nhau bởi dấu phẩy.
         Ví dụ output: "Thiết kế Titanium sang trọng, chip A17 Pro siêu mạnh, cổng USB-C tiện lợi, camera 48MP sắc nét, pin trâu cả ngày".
       `;

       const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
      });

      if (response.text) {
        setInputs(prev => ({
          ...prev,
          benefit: response.text.trim()
        }));
      }

    } catch (error) {
      console.error("Benefit Suggestion Error:", error);
      alert("AI đang bận, vui lòng thử lại sau!");
    } finally {
      setIsSuggestingBenefit(false);
    }
  };

  // Main generation function using AI
  const generateContent = async () => {
    setIsPostCopied(false);
    setIsCommentCopied(false);
    setIsAllCopied(false);

    // If AI mode is off or API key is missing, use static
    if (!useAI || !process.env.API_KEY) {
      generateStaticContent();
      return;
    }

    setIsGenerating(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const stylePrompts: Record<KolStyleKey, string> = {
        kol_boc_phot: "Phong cách 'Bóc phốt Idol': Giật tít như đang tố cáo KOL lừa dối, dùng hàng giả, hoặc có scandal. Nhưng thực tế là 'bóc' việc KOL dùng sản phẩm này quá đẹp/tốt mà giấu fan.",
        kol_canh_bao: "Phong cách 'Cảnh báo đu trend': Cảnh báo người dùng về hậu quả khi bắt chước KOL (hậu quả là bị nghiện sản phẩm, bị đẹp quá mức). Tạo cảm giác cấp bách.",
        kol_to_mo: "Phong cách 'Tò mò/Soi mói': Zoom vào chi tiết nhỏ trong ảnh/video của KOL (túi xách, bàn trang điểm) để tìm ra vật thể lạ (sản phẩm). Kích thích sự tò mò tột độ.",
        kol_hoi_han: "Phong cách 'Hối hận': Đóng vai fan hâm mộ đã bỏ qua lời khuyên của KOL và giờ hối hận. Hoặc đóng vai anti-fan đã trách nhầm KOL.",
        kol_tam_linh: "Phong cách 'Tâm linh/Vía': Kết nối sự thành công/may mắn của KOL với sản phẩm (vía tốt, vật phẩm phong thủy, tín hiệu vũ trụ).",
        kol_kinh_di: "Phong cách 'Kinh dị/Shock': Mô tả những hình ảnh 'đáng sợ' (mặt mộc xấu, sự cố) của KOL trước khi dùng sản phẩm, hoặc sự thay đổi 'rùng mình' (theo hướng tốt) sau khi dùng.",
        kol_hai_huoc: "Phong cách 'Hài hước/Lầy lội': Kể về những tình huống dở khóc dở cười, sự cố 'ố dề' của KOL liên quan đến sản phẩm. Dùng ngôn ngữ Gen Z vui nhộn."
      };

      const systemInstruction = `
      BẠN LÀ MỘT BẬC THẦY 'CLICKBAIT' VÀ CHUYÊN GIA SÁNG TẠO NỘI DUNG VIRAL VỀ SHOWBIZ.

      QUY TẮC ĐỊNH DẠNG QUAN TRỌNG NHẤT (BẮT BUỘC): 
      1. SỬ DỤNG KÝ TỰ XUỐNG DÒNG (\\n\\n) ĐỂ TÁCH CÁC ĐOẠN VĂN. KHÔNG VIẾT DÍNH LIỀN.
      2. TRÌNH BÀY THOÁNG MẮT, DỄ ĐỌC TRÊN ĐIỆN THOẠI.
      3. BÀI ĐĂNG (CAPTION) PHẢI NGẮN GỌN (DƯỚI 50 TỪ) NHƯNG ĐỦ Ý.

      MỤC TIÊU: NỘI DUNG PHẢI LẤP LỬNG, CẮT NGANG ĐỂ BẮT BUỘC KHÁCH HÀNG PHẢI BẤM VÀO COMMENT ĐỂ ĐỌC TIẾP.

      NHIỆM VỤ:
      Viết 01 Bài đăng Facebook (Post) và 01 Bình luận ghim (Seeding Comment) để bán sản phẩm: "${inputs.productName || "Sản phẩm"}"
      Dựa trên hình ảnh của KOL: "${inputs.kolName || "Người nổi tiếng"}"
      Bối cảnh/Tin đồn (nếu có): "${inputs.context || "Không có"}"
      Keyword lợi ích/Điểm mạnh: "${inputs.benefit || "Công dụng tuyệt vời"}"
      Link mua hàng: "${inputs.link || "[Link]"}"
      Phong cách chủ đạo: ${stylePrompts[inputs.style]}

      ----------------------------------
      YÊU CẦU 1: BÀI ĐĂNG (CAPTION) - CẤU TRÚC 3 PHẦN TÁCH BIỆT

      1. HEADLINE GIẬT GÂN (IN HOA, Icon sốc).
         [Xuống dòng \\n\\n]
      2. ĐÚNG 1-2 câu "nhử mồi" nói về sự việc của KOL nhưng TUYỆT ĐỐI KHÔNG giải thích rõ ràng, KHÔNG nhắc tên sản phẩm.
         [Xuống dòng \\n\\n]
      3. Mũi tên chỉ xuống 👇 và câu kêu gọi xem dưới bình luận (VD: "Sự thật ở dưới cmt", "Xem full ở dưới", "Bằng chứng ở dưới 👇").

      ----------------------------------
      YÊU CẦU 2: BÌNH LUẬN (SEEDING) - GIẢI MÃ & BÁN HÀNG - CHIA ĐOẠN RÕ RÀNG

      - Đoạn 1: Tiết lộ "thủ phạm" hoặc "bí mật" chính là sản phẩm. Giải thích vì sao KOL lại như vậy.
         [Xuống dòng \\n\\n]
      - Đoạn 2: Review chi tiết lợi ích "${inputs.benefit}". Khẳng định uy tín của KOL khi dùng sản phẩm này.
         [Xuống dòng \\n\\n]
      - Đoạn 3: Kêu gọi hành động và Link mua hàng.

      ----------------------------------
      Định dạng đầu ra JSON bắt buộc:
      {
        "post": "Nội dung caption với các ký tự \\n\\n để xuống dòng...",
        "comment": "Nội dung comment với các ký tự \\n\\n để xuống dòng..."
      }`;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: {
          parts: [{ text: `Viết content viral về ${inputs.kolName} dùng sản phẩm ${inputs.productName}. Context: ${inputs.context}. Phong cách ${inputs.style}. Nhớ quy tắc xuống dòng thoáng mắt.` }]
        },
        config: {
          systemInstruction: systemInstruction,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              post: { type: Type.STRING },
              comment: { type: Type.STRING }
            },
            required: ["post", "comment"]
          }
        }
      });

      const jsonResult = JSON.parse(response.text || "{}");

      if (jsonResult.post && jsonResult.comment) {
        setGeneratedPost(jsonResult.post);
        setGeneratedComment(jsonResult.comment);
      } else {
        generateStaticContent();
      }

    } catch (error) {
      console.error("AI Generation Error:", error);
      generateStaticContent();
    } finally {
      setIsGenerating(false);
    }
  };

  // Generate on mount
  useEffect(() => {
    generateStaticContent();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); 

  // Copy helpers
  const handleCopy = async (text: string, setCopiedState: React.Dispatch<React.SetStateAction<boolean>>) => {
    if ('clipboard' in navigator) {
      try {
        await navigator.clipboard.writeText(text);
        setCopiedState(true);
        setTimeout(() => setCopiedState(false), 2000);
        return;
      } catch (err) { console.error(err); }
    }
    const textArea = document.createElement("textarea");
    textArea.value = text;
    document.body.appendChild(textArea);
    textArea.select();
    try { document.execCommand('copy'); setCopiedState(true); setTimeout(() => setCopiedState(false), 2000); } catch (e) {}
    document.body.removeChild(textArea);
  };

  const copyPost = () => handleCopy(generatedPost, setIsPostCopied);
  const copyComment = () => handleCopy(generatedComment, setIsCommentCopied);
  const copyAll = () => handleCopy(`--- CAPTION ---\n${generatedPost}\n\n--- SEEDING COMMENT ---\n${generatedComment}`, setIsAllCopied);

  // Button config for KOL - Updated to match new styles
  const buttonConfig: { id: KolStyleKey; label: string; icon?: React.ReactNode; colorClass: string }[] = [
    { id: 'kol_boc_phot', label: 'Bóc phốt', icon: '🤬', colorClass: 'bg-red-100 text-red-700 border-red-500' },
    { id: 'kol_canh_bao', label: 'Cảnh báo', icon: <ShieldAlert className="w-3 h-3"/>, colorClass: 'bg-yellow-100 text-yellow-700 border-yellow-500' },
    { id: 'kol_to_mo', label: 'Tò mò', icon: <Eye className="w-3 h-3"/>, colorClass: 'bg-purple-100 text-purple-700 border-purple-500' },
    { id: 'kol_hoi_han', label: 'Hối hận', icon: <HeartHandshake className="w-3 h-3"/>, colorClass: 'bg-orange-100 text-orange-700 border-orange-500' },
    { id: 'kol_tam_linh', label: 'Tâm linh', icon: <Sparkles className="w-3 h-3"/>, colorClass: 'bg-indigo-100 text-indigo-700 border-indigo-500' },
    { id: 'kol_kinh_di', label: 'Kinh dị', icon: <Skull className="w-3 h-3"/>, colorClass: 'bg-gray-800 text-white border-gray-600' },
    { id: 'kol_hai_huoc', label: 'Hài hước', icon: <Laugh className="w-3 h-3"/>, colorClass: 'bg-lime-100 text-lime-700 border-lime-500' },
  ];

  return (
    <div className="min-h-screen p-4 font-sans text-slate-800">
      <div className="max-w-[1400px] mx-auto grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Left Column: Input Panel */}
        <div className="space-y-6 lg:col-span-1">
          <div className="bg-white rounded-xl shadow-md overflow-hidden border border-purple-100">
            {/* Header */}
            <div className="bg-gradient-to-r from-purple-600 to-pink-600 p-4 flex justify-between items-center">
              <h1 className="text-xl font-bold flex items-center gap-2 text-white uppercase">
                <AlertTriangle className="w-6 h-6 text-white" />
                KOL Viral Options
              </h1>
              <button 
                onClick={() => setUseAI(!useAI)}
                className={`flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold transition-all border
                  ${useAI 
                    ? 'bg-white text-purple-600 border-white shadow-sm' 
                    : 'bg-purple-800 text-purple-200 border-purple-500'}`}
              >
                {useAI ? <Sparkles className="w-3 h-3" /> : <Zap className="w-3 h-3" />}
                {useAI ? 'AI: ON' : 'AI: OFF'}
              </button>
            </div>

            {/* Body */}
            <div className="p-6">
              <p className="text-slate-500 mb-6 text-sm">
                Dùng sự nổi tiếng của KOL để tạo content <strong>tò mò, gây sốc</strong>.
              </p>

              <div className="space-y-4">
                {/* Inputs */}
                <div>
                  <label className="block text-sm font-semibold mb-1 text-purple-800">Tên Người Nổi Tiếng / Idol</label>
                  <input
                    type="text"
                    name="kolName"
                    placeholder="VD: Sơn Tùng, Ngọc Trinh, Hà Linh..."
                    className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-purple-500 focus:outline-none transition-shadow bg-slate-50"
                    value={inputs.kolName}
                    onChange={handleInputChange}
                  />
                </div>

                {/* PRODUCT NAME SEPARATE */}
                <div>
                  <label className="block text-sm font-semibold mb-1 text-purple-800">Tên Sản Phẩm</label>
                  <input
                      type="text"
                      name="productName"
                      placeholder="Tên sản phẩm..."
                      className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-purple-500 focus:outline-none bg-slate-50 transition-shadow"
                      value={inputs.productName}
                      onChange={handleInputChange}
                  />
                </div>

                {/* PRODUCT DESC */}
                <div>
                   <label className="block text-sm font-semibold mb-1 text-purple-800">Mô tả sơ bộ về sản phẩm</label>
                   <textarea
                    name="productDescription"
                    placeholder="Nhập mô tả ngắn gọn về sản phẩm để AI hiểu rõ hơn..."
                    className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-purple-500 focus:outline-none transition-shadow h-20 resize-y bg-slate-50 text-sm"
                    value={inputs.productDescription}
                    onChange={handleInputChange}
                  />
                </div>

                 {/* AI ACTION */}
                <div className="flex justify-center -my-2 z-10 relative">
                   <button
                      onClick={handleSuggestBenefits}
                      disabled={isSuggestingBenefit || (!inputs.productName && !inputs.productDescription)}
                      className="text-xs flex items-center gap-1.5 bg-purple-600 text-white px-4 py-1.5 rounded-full hover:bg-purple-700 transition-all shadow-md transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                      {isSuggestingBenefit ? <Loader2 className="w-3 h-3 animate-spin"/> : <Sparkles className="w-3 h-3"/>}
                      {isSuggestingBenefit ? 'Đang phân tích...' : 'AI Phân Tích & Gợi Ý Điểm Mạnh'}
                      <ArrowDown className="w-3 h-3"/>
                    </button>
                </div>

                {/* BENEFIT SEPARATE */}
                <div>
                  <label className="block text-sm font-semibold text-purple-800 mb-1">Điểm mạnh / USP (Kết quả AI)</label>
                  <textarea
                      name="benefit"
                      placeholder="AI sẽ tự động điền các điểm mạnh vào đây..."
                      className="w-full p-3 border border-purple-200 rounded-lg focus:ring-2 focus:ring-purple-500 focus:outline-none transition-shadow h-24 resize-y bg-purple-50/50 text-purple-900 font-medium"
                      value={inputs.benefit}
                      onChange={handleInputChange}
                  />
                </div>

                {/* LINK SEPARATE */}
                <div>
                   <label className="block text-sm font-semibold mb-1 text-purple-800">Link mua hàng</label>
                   <input
                      type="text"
                      name="link"
                      placeholder="https://..."
                      className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-purple-500 focus:outline-none bg-slate-50 transition-shadow"
                      value={inputs.link}
                      onChange={handleInputChange}
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold mb-1 text-purple-800">Ngữ cảnh / Tin đồn (Optional)</label>
                  <input
                    type="text"
                    name="context"
                    placeholder="VD: Bị bắt gặp ở sân bay, mới chia tay, lộ clip..."
                    className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-purple-500 focus:outline-none transition-shadow bg-slate-50"
                    value={inputs.context}
                    onChange={handleInputChange}
                  />
                </div>

                {/* Style Buttons */}
                <div>
                  <label className="block text-sm font-semibold mb-2 text-purple-800">Phong cách giật tít</label>
                  <div className="grid grid-cols-2 gap-2">
                    {buttonConfig.map((btn) => (
                      <button 
                        key={btn.id}
                        onClick={() => setStyle(btn.id)} 
                        className={`p-2 rounded-lg text-xs font-bold transition-all flex items-center justify-center gap-1.5
                          ${inputs.style === btn.id 
                            ? `${btn.colorClass} border-2 shadow-sm scale-[1.02]` 
                            : 'bg-white text-slate-500 border border-slate-200 hover:bg-purple-50 hover:text-purple-600 hover:border-purple-200'
                          }`}
                      >
                        {btn.icon} {btn.label}
                      </button>
                    ))}
                  </div>
                </div>

                <button
                  onClick={generateContent}
                  disabled={isGenerating}
                  className={`w-full font-bold py-3.5 rounded-xl flex items-center justify-center gap-2 transition-all mt-4 shadow-lg shadow-purple-200 transform 
                    ${isGenerating 
                      ? 'bg-slate-300 cursor-not-allowed' 
                      : 'bg-gradient-to-r from-purple-500 to-pink-600 hover:from-purple-600 hover:to-pink-700 active:bg-purple-800 hover:-translate-y-0.5 text-white'}`}
                >
                  {isGenerating ? (
                    <><RefreshCw className="w-5 h-5 animate-spin" /> Đang "Hóng Biến"...</>
                  ) : (
                    <><Sparkles className="w-5 h-5" /> Tạo Content KOL</>
