  // Outputs
  const [hookResult, setHookResult] = useState('');
  const [scriptResult, setScriptResult] = useState('');
  const [imagePrompt, setImagePrompt] = useState('');
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);

  // Loading States
  const [isGeneratingHook, setIsGeneratingHook] = useState(false);
  const [isGeneratingScript, setIsGeneratingScript] = useState(false);
  const [isGeneratingImgPrompt, setIsGeneratingImgPrompt] = useState(false);
  const [isRenderingImage, setIsRenderingImage] = useState(false);

  // UI States
  const [tip, setTip] = useState('');
  const [showToast, setShowToast] = useState(false);

  const tips = [
    "Mẹo AI: Đôi khi AI viết hơi dài, bạn có thể tự cắt ngắn bớt cho súc tích.",
    "Mẹo AI: Nếu Hook chưa đủ 'phê', hãy thử đổi phong cách sang 'Drama' hoặc 'Nỗi sợ'.",
    "Mẹo AI: Thêm các con số cụ thể vào mô tả sản phẩm để AI viết chính xác hơn.",
    "Mẹo AI: Nếu chữ trên ảnh bị lỗi dấu, hãy thử bấm 'Vẽ Ảnh' lại lần nữa."
  ];

  const handleGenerateHook = async () => {
    if (!productName.trim()) { alert("Bạn ơi, nhập tên sản phẩm giúp mình với!"); return; }

    setIsGeneratingHook(true);
    setHookResult('');
    setScriptResult('');
    setImagePrompt('');
    setGeneratedImage(null);

    try {
        const desc = productDesc || "giải quyết vấn đề của khách hàng";
        const result = await generateHook(productName, desc, hookStyle);
        setHookResult(result);
        setTip(tips[Math.floor(Math.random() * tips.length)]);
    } catch (e) {
        console.error(e);
        setHookResult("Lỗi kết nối. Thử lại giúp mình nhé!");
    } finally {
        setIsGeneratingHook(false);
    }
  };

  const handleGenerateScript = async () => {
    if (!hookResult) return;
    setIsGeneratingScript(true);
    try {
        const result = await generateScriptFromHook(hookResult, productName, productDesc);
        setScriptResult(result);
    } catch (e) {
        console.error(e);
