                    <label className="block text-xs font-bold font-display text-slate-600 mb-2 uppercase tracking-wider">1. Chủ đề & Bối cảnh</label>
                    <div className="flex flex-wrap gap-1.5 mb-2 max-h-24 overflow-y-auto custom-scrollbar">
                        {PROMPT_TOPICS.map(topic => (
                            <button key={topic} onClick={() => setInputText(topic)} className="px-2 py-1 rounded bg-slate-100 text-slate-600 text-[10px] font-semibold hover:bg-orange-100 hover:text-orange-600 transition-colors border border-transparent hover:border-orange-200">
                                {topic}
