                    </div>
                    <div className="flex items-center gap-2 mb-2">
                        <input type="text" value={inputText} onChange={(e) => setInputText(e.target.value)} placeholder="Nhập chủ đề..." className="flex-1 p-2.5 border border-slate-200 rounded-lg text-sm focus:border-orange-500 focus:ring-2 focus:ring-orange-100 outline-none font-body" />
                        <button onClick={handleSuggestIdea} disabled={isSuggestingIdea} className="bg-orange-100 hover:bg-orange-200 text-orange-700 p-2.5 rounded-lg font-bold flex items-center gap-2 text-xs" title="AI Gợi ý">
