                        </button>
                    </div>
                    <textarea value={description} onChange={(e) => setDescription(e.target.value)} placeholder="Mô tả chi tiết..." className="w-full p-2.5 border border-slate-200 rounded-lg text-xs h-16 resize-none focus:border-orange-500 focus:ring-2 focus:ring-orange-100 outline-none font-body"/>
