  const copyAllPrompts = () => { generatedPrompts.forEach(p => navigator.clipboard.writeText(p.prompt)); alert("Đã copy!"); };
  const copyBananaPrompt = () => { navigator.clipboard.writeText(generatedBananaPrompt); alert("Copied!"); };
  const copyAllVideoPrompts = () => { videoPrompts.forEach(p => navigator.clipboard.writeText(p.prompt)); alert("Copied!"); };
  const copyGrokPrompt = () => { navigator.clipboard.writeText(grokResult); alert("Đã copy Prompt cho Grok!"); };

  const renderResultModalContent = () => {
      switch (activeTab) {
          case 'prompts': return (
              <div className="space-y-6">
