                        <div>
                            <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">Tỉ lệ ảnh</label>
                            <select value={bananaAspectRatio} onChange={(e) => setBananaAspectRatio(e.target.value)} className="w-full p-2 border border-slate-200 rounded-lg text-sm font-body bg-white"><option value="--ar 2:3">2:3 (Chân dung)</option><option value="--ar 16:9">16:9 (Ngang)</option><option value="--ar 1:1">1:1 (Vuông)</option></select>
                        </div>
                    </div>
                    <button onClick={generateBananaPrompt} disabled={isBananaGenerating || !charImage || !prodImage} className="w-full py-3 bg-yellow-400 hover:bg-yellow-500 text-yellow-900 font-bold rounded-xl shadow-md transition-all flex items-center justify-center gap-2">{isBananaGenerating ? <RefreshCw className="animate-spin"/> : <Banana/>} Tạo Prompt Nano Banana</button>
                    {bananaError && <p className="text-red-500 text-xs mt-2 text-center">{bananaError}</p>}
                </div>
            </div>
            )}

            {activeTab === 'philosophy' && (
            <div className="animate-in fade-in duration-300 space-y-4">
                <div className="bg-white rounded-2xl shadow-sm p-6 border border-slate-200 text-center">
                    <h3 className="text-lg font-bold font-display text-slate-800 mb-2">Trích dẫn & Triết lý sống</h3>
                    <p className="text-slate-500 text-sm mb-6 max-w-lg mx-auto font-body">Tạo ảnh infographic/quote deep, ý nghĩa để đăng Story hoặc Reels.</p>

                    <div className="bg-slate-50 p-6 rounded-xl border border-slate-100 mb-6 relative">
                        <Quote className="absolute top-4 left-4 text-slate-200 w-8 h-8"/>
                        {isQuoteLoading ? (
                             <div className="py-8 flex justify-center"><RefreshCw className="animate-spin text-slate-400"/></div>
                        ) : currentQuote ? (
                            <div className="relative z-10">
                                <p className="text-xl font-display font-bold text-slate-800 mb-4 leading-relaxed">"{currentQuote.text}"</p>
                                <p className="text-sm font-medium text-violet-600">— {currentQuote.author}</p>
                                <span className="inline-block mt-4 text-[10px] bg-white border border-slate-200 px-2 py-1 rounded-full text-slate-500 uppercase tracking-wider">{currentQuote.tag}</span>
                            </div>
                        ) : (
                            <div className="py-8 text-slate-400 text-sm italic">Nhấn nút bên dưới để tìm một câu trích dẫn hay...</div>
                        )}
                        <Quote className="absolute bottom-4 right-4 text-slate-200 w-8 h-8 transform rotate-180"/>
                    </div>

                    <div className="flex justify-center gap-4 mb-8">
                         <button onClick={generateQuote} className="px-6 py-2 bg-slate-800 text-white rounded-full font-bold text-sm hover:bg-slate-900 transition flex items-center gap-2 shadow-lg"><RefreshCw size={14}/> Đổi câu khác</button>
                    </div>

                    {/* NEW: 3 COLUMN CONFIGURATION GRID */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 text-left border-t border-slate-100 pt-6">
                        {/* Column 1: Style */}
                        <div className="space-y-3">
                             <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">1. Phong cách (Style)</label>
                             <div className="space-y-2 max-h-60 overflow-y-auto custom-scrollbar pr-1">
                                {INFO_STYLES.map(s => (
                                    <button 
                                        key={s.id} 
                                        onClick={() => setPhilosophyConfig({...philosophyConfig, style: s.id})}
                                        className={`w-full p-3 rounded-lg border text-left transition-all relative ${philosophyConfig.style === s.id ? 'border-purple-500 bg-purple-50 ring-1 ring-purple-200' : 'border-slate-200 hover:bg-slate-50'}`}
                                    >
                                        <div className="font-bold text-sm text-slate-700">{s.name}</div>
                                        <div className="text-[10px] text-slate-500 mt-0.5 leading-tight">{s.desc}</div>
                                        {philosophyConfig.style === s.id && <CheckCircle2 className="absolute top-3 right-3 text-purple-600 w-4 h-4"/>}
                                    </button>
                                ))}
                             </div>
                        </div>

                        {/* Column 2: Layout */}
                        <div className="space-y-3">
                             <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">2. Bố cục (Concept)</label>
                             <div className="space-y-2 max-h-60 overflow-y-auto custom-scrollbar pr-1">
                                {INFO_LAYOUTS.map(l => (
                                    <button 
                                        key={l.id} 
                                        onClick={() => setPhilosophyConfig({...philosophyConfig, layout: l.id})}
                                        className={`w-full p-3 rounded-lg border text-left transition-all relative ${philosophyConfig.layout === l.id ? 'border-purple-500 bg-purple-50 ring-1 ring-purple-200' : 'border-slate-200 hover:bg-slate-50'}`}
                                    >
                                        <div className="flex items-center gap-2 mb-1">
                                            <span className="text-slate-400">{l.icon}</span>
                                            <span className="font-bold text-sm text-slate-700">{l.name}</span>
                                        </div>
                                        <div className="text-[10px] text-slate-500 leading-tight pl-6">{l.desc}</div>
                                        {philosophyConfig.layout === l.id && <CheckCircle2 className="absolute top-3 right-3 text-purple-600 w-4 h-4"/>}
                                    </button>
                                ))}
                             </div>
                        </div>

                        {/* Column 3: Ratio */}
                        <div className="space-y-3">
                             <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">3. Khung hình (Ratio)</label>
                             <div className="space-y-2 max-h-60 overflow-y-auto custom-scrollbar pr-1">
                                {INFO_RATIOS.map(r => (
                                    <button 
                                        key={r.id} 
                                        onClick={() => setPhilosophyConfig({...philosophyConfig, ratio: r.id})}
                                        className={`w-full p-3 rounded-lg border text-left transition-all relative flex items-center gap-3 ${philosophyConfig.ratio === r.id ? 'border-purple-500 bg-purple-50 ring-1 ring-purple-200' : 'border-slate-200 hover:bg-slate-50'}`}
                                    >
                                        <div className={`p-2 rounded bg-white border ${philosophyConfig.ratio === r.id ? 'border-purple-200 text-purple-600' : 'border-slate-200 text-slate-400'}`}>
                                            {r.icon}
                                        </div>
                                        <div>
                                            <div className="font-bold text-sm text-slate-700">{r.id}</div>
                                            <div className="text-[10px] text-slate-500">{r.desc}</div>
                                        </div>
                                        {philosophyConfig.ratio === r.id && <CheckCircle2 className="absolute top-1/2 -translate-y-1/2 right-3 text-purple-600 w-4 h-4"/>}
                                    </button>
                                ))}
                             </div>
                        </div>
                    </div>

                    <button onClick={handleGenerateQuotePrompt} disabled={isQuotePromptGenerating || !currentQuote} className="mt-8 w-full md:w-auto px-10 py-3 bg-gradient-to-r from-purple-600 to-indigo-600 text-white font-bold rounded-xl shadow-lg hover:shadow-purple-500/30 transition-all flex items-center justify-center gap-2 mx-auto transform hover:-translate-y-0.5 active:scale-95">
                        {isQuotePromptGenerating ? <RefreshCw className="animate-spin" size={20}/> : <Wand2 size={20}/>} Tạo ảnh Infographic
                    </button>
                </div>
            </div>
            )}
      </div>

      {showResultModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-white rounded-2xl w-full max-w-5xl max-h-[90vh] flex flex-col shadow-2xl animate-in zoom-in-95 duration-200">
                <div className="flex justify-between items-center p-4 border-b border-gray-100"><h3 className="font-bold font-display text-gray-800 text-lg flex items-center gap-2"><Sparkles size={18} className="text-orange-600"/> Kết quả Prompt</h3><button onClick={() => setShowResultModal(false)} className="p-2 hover:bg-gray-100 rounded-full transition-colors text-gray-500"><X size={24}/></button></div>
                <div className="flex-1 lg:overflow-y-auto h-auto p-6 custom-scrollbar bg-gray-50">{renderResultModalContent()}</div>
                <div className="p-4 border-t border-gray-100 bg-white rounded-b-2xl flex justify-end"><button onClick={() => setShowResultModal(false)} className="px-6 py-2 bg-gray-100 hover:bg-gray-200 text-gray-700 font-bold rounded-xl transition-colors font-display">Đóng</button></div>
            </div>
        </div>
      )}
    </div>
  );
};
